import React, { useState, useEffect } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useBalance } from '../context/BalanceContext';
import { useUser } from '../context/UserContext';
import YooMoneyModal from './YooMoneyModal'; // Импортируем новый компонент
import logo from '../logo.png';

function Header() {
  const { balance } = useBalance();
  const { currentUser, logout, unreadCount, unreadSupportCount, isSupport, isAdmin } = useUser();
  const [isBalanceModalOpen, setIsBalanceModalOpen] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [onlineUsers, setOnlineUsers] = useState(0);
  const navigate = useNavigate();

  // Симуляция онлайн пользователей
  useEffect(() => {
    const randomOnline = Math.floor(Math.random() * 20) + 5;
    setOnlineUsers(randomOnline);

    const interval = setInterval(() => {
      const newOnline = Math.floor(Math.random() * 20) + 5;
      setOnlineUsers(newOnline);
    }, 30000);

    return () => clearInterval(interval);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/login');
    setIsMenuOpen(false);
  };

  return (
    <>
      <header className="header">
        <div className="header-content">
          <div className="logo-container" onClick={() => navigate('/')}>
            <img 
              src={logo} 
              alt="Visor Market" 
              className="logo-image"
            />
          </div>
          
          {currentUser && (
            <nav className="nav-links nav-left">
              <NavLink to="/" end>Главная</NavLink>
              <NavLink to="/buy">Купить</NavLink>
              <NavLink to="/sell">Продать</NavLink>
              <NavLink to="/listings">Объявления</NavLink>
              {isAdmin() && (
                <NavLink to="/admin">Админка</NavLink>
              )}
            </nav>
          )}

          <div className="header-right">
            {currentUser ? (
              <>
                <div className="online-indicator">
                  <span className="online-dot"></span>
                  <span>{onlineUsers} онлайн</span>
                </div>

                <div className="wallet-info">
                  <div 
                    className="balance" 
                    onClick={() => setIsBalanceModalOpen(true)}
                  >
                    <span>💰</span>
                    <span>{balance.toLocaleString()} ₽</span>
                  </div>
                  
                  <div 
                    className="avatar" 
                    onClick={() => setIsMenuOpen(!isMenuOpen)}
                    style={{ 
                      position: 'relative',
                      border: isSupport() ? '2px solid var(--success)' : 
                              isAdmin() ? '2px solid var(--primary)' : 'none',
                      cursor: 'pointer'
                    }}
                  >
                    {currentUser.username?.[0]?.toUpperCase() || 'U'}
                    {unreadCount > 0 && (
                      <span style={{
                        position: 'absolute',
                        top: '-4px',
                        right: '-4px',
                        background: 'var(--danger)',
                        color: 'white',
                        borderRadius: '50%',
                        width: '16px',
                        height: '16px',
                        fontSize: '10px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        border: '2px solid white'
                      }}>
                        {unreadCount}
                      </span>
                    )}
                    {isSupport() && (
                      <div style={{
                        position: 'absolute',
                        bottom: '-4px',
                        right: '-4px',
                        background: 'var(--success)',
                        color: 'white',
                        borderRadius: '50%',
                        width: '16px',
                        height: '16px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '10px',
                        border: '2px solid white'
                      }}>
                        🛟
                      </div>
                    )}
                  </div>

                  {/* Выпадающее меню (без изменений) */}
                  {isMenuOpen && (
                    <div style={{
                      position: 'absolute',
                      top: '60px',
                      right: '20px',
                      background: 'white',
                      borderRadius: '8px',
                      boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                      padding: '0.75rem',
                      zIndex: 1000,
                      minWidth: '200px',
                      border: '1px solid var(--border)'
                    }}>
                      {/* ... содержимое меню ... */}
                      <div style={{ marginBottom: '0.5rem', padding: '0.5rem', borderBottom: '1px solid var(--border)' }}>
                        <div style={{ fontWeight: '600' }}>{currentUser.firstName} {currentUser.lastName}</div>
                        <div style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>@{currentUser.username}</div>
                        {isSupport() && <div style={{ fontSize: '0.8rem', color: 'var(--success)' }}>🛟 Техподдержка</div>}
                        {isAdmin() && <div style={{ fontSize: '0.8rem', color: 'var(--primary)' }}>👑 Администратор</div>}
                      </div>
                      
                      <NavLink 
                        to={`/user/${currentUser.id}`} 
                        style={{ 
                          display: 'block', 
                          padding: '0.5rem 0.75rem',
                          textDecoration: 'none',
                          color: 'var(--dark)',
                          borderRadius: '4px',
                          fontSize: '0.9rem',
                          transition: 'background 0.2s',
                          marginBottom: '0.25rem'
                        }}
                        onClick={() => setIsMenuOpen(false)}
                        onMouseEnter={(e) => e.target.style.background = 'var(--light)'}
                        onMouseLeave={(e) => e.target.style.background = 'transparent'}
                      >
                        👤 Мой профиль
                      </NavLink>

                      <NavLink 
                        to="/messages" 
                        style={{ 
                          display: 'block', 
                          padding: '0.5rem 0.75rem',
                          textDecoration: 'none',
                          color: 'var(--dark)',
                          borderRadius: '4px',
                          fontSize: '0.9rem',
                          transition: 'background 0.2s',
                          position: 'relative',
                          marginBottom: '0.25rem'
                        }}
                        onClick={() => setIsMenuOpen(false)}
                        onMouseEnter={(e) => e.target.style.background = 'var(--light)'}
                        onMouseLeave={(e) => e.target.style.background = 'transparent'}
                      >
                        💬 Сообщения
                        {unreadCount > 0 && (
                          <span style={{
                            marginLeft: '0.5rem',
                            background: 'var(--danger)',
                            color: 'white',
                            borderRadius: '50%',
                            width: '18px',
                            height: '18px',
                            fontSize: '10px',
                            display: 'inline-flex',
                            alignItems: 'center',
                            justifyContent: 'center'
                          }}>
                            {unreadCount}
                          </span>
                        )}
                      </NavLink>

                      {(isSupport() || isAdmin()) && (
                        <NavLink 
                          to="/support" 
                          style={{ 
                            display: 'block', 
                            padding: '0.5rem 0.75rem',
                            textDecoration: 'none',
                            color: 'var(--dark)',
                            borderRadius: '4px',
                            fontSize: '0.9rem',
                            transition: 'background 0.2s',
                            position: 'relative',
                            marginBottom: '0.25rem'
                          }}
                          onClick={() => setIsMenuOpen(false)}
                          onMouseEnter={(e) => e.target.style.background = 'var(--light)'}
                          onMouseLeave={(e) => e.target.style.background = 'transparent'}
                        >
                          🛟 Поддержка
                          {unreadSupportCount > 0 && (
                            <span style={{
                              marginLeft: '0.5rem',
                              background: 'var(--danger)',
                              color: 'white',
                              borderRadius: '50%',
                              width: '18px',
                              height: '18px',
                              fontSize: '10px',
                              display: 'inline-flex',
                              alignItems: 'center',
                              justifyContent: 'center'
                            }}>
                              {unreadSupportCount}
                            </span>
                          )}
                        </NavLink>
                      )}

                      {isAdmin() && (
                        <NavLink 
                          to="/admin" 
                          style={{ 
                            display: 'block', 
                            padding: '0.5rem 0.75rem',
                            textDecoration: 'none',
                            color: 'var(--dark)',
                            borderRadius: '4px',
                            fontSize: '0.9rem',
                            transition: 'background 0.2s',
                            marginBottom: '0.25rem'
                          }}
                          onClick={() => setIsMenuOpen(false)}
                          onMouseEnter={(e) => e.target.style.background = 'var(--light)'}
                          onMouseLeave={(e) => e.target.style.background = 'transparent'}
                        >
                          👑 Админка
                        </NavLink>
                      )}

                      <button 
                        onClick={handleLogout}
                        style={{
                          display: 'block',
                          width: '100%',
                          padding: '0.5rem 0.75rem',
                          background: 'none',
                          border: 'none',
                          textAlign: 'left',
                          cursor: 'pointer',
                          color: 'var(--danger)',
                          borderRadius: '4px',
                          fontSize: '0.9rem',
                          transition: 'background 0.2s',
                          marginTop: '0.25rem'
                        }}
                        onMouseEnter={(e) => e.target.style.background = 'var(--light)'}
                        onMouseLeave={(e) => e.target.style.background = 'transparent'}
                      >
                        🚪 Выйти
                      </button>
                    </div>
                  )}
                </div>
              </>
            ) : (
              <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                <div className="online-indicator">
                  <span className="online-dot"></span>
                  <span>{onlineUsers} онлайн</span>
                </div>
                <button
                  className="btn btn-primary"
                  onClick={() => navigate('/login')}
                  style={{ width: 'auto' }}
                >
                  Войти
                </button>
              </div>
            )}
          </div>
        </div>
      </header>

      {/* Новое модальное окно для пополнения */}
      <YooMoneyModal 
        isOpen={isBalanceModalOpen}
        onClose={() => setIsBalanceModalOpen(false)}
      />
    </>
  );
}

export default Header;