import React, { createContext, useState, useContext, useEffect } from 'react';
import { useUser } from './UserContext';
import { 
  transactionsRef, 
  sbpPaymentsRef,
  withdrawRequestsRef,
  onDataChange,
  pushData,
  updateData
} from '../firebase';

const BalanceContext = createContext();

export function useBalance() {
  return useContext(BalanceContext);
}

export function BalanceProvider({ children }) {
  const { currentUser, users } = useUser();
  const [balance, setBalance] = useState(0);
  const [platformBalance, setPlatformBalance] = useState(0);
  const [transactions, setTransactions] = useState([]);
  const [sbpPayments, setSbpPayments] = useState([]);
  const [withdrawRequests, setWithdrawRequests] = useState([]);

  // Загрузка баланса пользователя из localStorage
  useEffect(() => {
    if (currentUser) {
      const userBalanceKey = `visor_balance_${currentUser.id}`;
      const savedBalance = localStorage.getItem(userBalanceKey);
      if (savedBalance) setBalance(Number(savedBalance));
    }
    
    const savedPlatform = localStorage.getItem('visor_platform');
    if (savedPlatform) setPlatformBalance(Number(savedPlatform));
  }, [currentUser]);

  // Сохранение баланса
  useEffect(() => {
    if (currentUser) {
      const userBalanceKey = `visor_balance_${currentUser.id}`;
      localStorage.setItem(userBalanceKey, balance);
    }
    localStorage.setItem('visor_platform', platformBalance);
  }, [balance, platformBalance, currentUser]);

  // Подписка на транзакции
  useEffect(() => {
    const unsubscribe = onDataChange('transactions', (data) => {
      if (data) {
        const transactionsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setTransactions(transactionsArray);
      } else {
        setTransactions([]);
      }
    });

    return unsubscribe;
  }, []);

  // Подписка на СБП платежи
  useEffect(() => {
    const unsubscribe = onDataChange('sbpPayments', (data) => {
      if (data) {
        const paymentsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setSbpPayments(paymentsArray);
      } else {
        setSbpPayments([]);
      }
    });

    return unsubscribe;
  }, []);

  // Подписка на заявки на вывод
  useEffect(() => {
    const unsubscribe = onDataChange('withdrawRequests', (data) => {
      if (data) {
        const requestsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setWithdrawRequests(requestsArray);
      } else {
        setWithdrawRequests([]);
      }
    });

    return unsubscribe;
  }, []);

  // ===== ПОПОЛНЕНИЕ =====
  const deposit = async (amount, method) => {
    if (!currentUser) {
      return { success: false, error: 'Пользователь не авторизован' };
    }

    const userBalanceKey = `visor_balance_${currentUser.id}`;
    const currentBalance = localStorage.getItem(userBalanceKey) || '0';
    const newBalance = Number(currentBalance) + amount;
    localStorage.setItem(userBalanceKey, newBalance.toString());

    setBalance(prev => prev + amount);

    const transaction = {
      userId: currentUser.id,
      username: currentUser.username,
      type: 'deposit',
      amount,
      method,
      date: new Date().toISOString(),
      status: 'completed'
    };
    
    await pushData('transactions', transaction);
    
    return { success: true };
  };

  // Пополнение для конкретного пользователя (для админа)
  const depositForUser = async (amount, method, userId) => {
    const user = users.find(u => u.id === userId);
    if (!user) {
      return { success: false, error: 'Пользователь не найден' };
    }

    const userBalanceKey = `visor_balance_${userId}`;
    const currentBalance = localStorage.getItem(userBalanceKey) || '0';
    const newBalance = Number(currentBalance) + amount;
    localStorage.setItem(userBalanceKey, newBalance.toString());

    if (currentUser && currentUser.id === userId) {
      setBalance(prev => prev + amount);
    }

    const transaction = {
      userId: userId,
      username: user.username,
      type: 'deposit',
      amount,
      method,
      date: new Date().toISOString(),
      status: 'completed'
    };
    
    await pushData('transactions', transaction);
    
    return { success: true };
  };

  // ===== СБП ПЛАТЕЖИ =====
  const createSbpPayment = async (amount, cardNumber) => {
    if (!currentUser) {
      return { success: false, error: 'Пользователь не авторизован' };
    }

    const payment = {
      userId: currentUser.id,
      username: currentUser.username,
      amount: Number(amount),
      cardNumber,
      date: new Date().toISOString(),
      status: 'pending'
    };

    const result = await pushData('sbpPayments', payment);
    const paymentId = result.key;

    const transaction = {
      userId: currentUser.id,
      username: currentUser.username,
      type: 'sbp_request',
      amount: Number(amount),
      cardNumber,
      date: new Date().toISOString(),
      status: 'pending',
      paymentId: paymentId
    };

    await pushData('transactions', transaction);

    return { success: true, paymentId };
  };

  const approveSbpPayment = async (paymentId, adminId) => {
    try {
      const payment = sbpPayments.find(p => p.id === paymentId);
      
      if (!payment) {
        return { success: false, error: 'Платеж не найден' };
      }

      await updateData(`sbpPayments/${paymentId}`, {
        ...payment,
        status: 'approved',
        confirmedBy: adminId,
        confirmedAt: new Date().toISOString()
      });

      await depositForUser(payment.amount, 'sbp', payment.userId);

      return { success: true };
    } catch (error) {
      console.error('Ошибка подтверждения платежа:', error);
      return { success: false, error: error.message };
    }
  };

  const rejectSbpPayment = async (paymentId, reason) => {
    try {
      const payment = sbpPayments.find(p => p.id === paymentId);
      
      await updateData(`sbpPayments/${paymentId}`, {
        ...payment,
        status: 'rejected',
        rejectReason: reason,
        rejectedAt: new Date().toISOString()
      });

      return { success: true };
    } catch (error) {
      console.error('Ошибка отклонения платежа:', error);
      return { success: false, error: error.message };
    }
  };

  const getAllSbpPayments = () => sbpPayments;

  const getUserSbpPayments = (userId) => {
    return sbpPayments.filter(p => p.userId === userId);
  };

  // ===== ВЫВОД СРЕДСТВ =====
  const createWithdrawRequest = async (requestData) => {
    if (!currentUser) {
      return { success: false, error: 'Пользователь не авторизован' };
    }

    if (balance < requestData.amount) {
      return { success: false, error: 'Недостаточно средств' };
    }

    const result = await pushData('withdrawRequests', requestData);
    
    const userBalanceKey = `visor_balance_${currentUser.id}`;
    const currentBalance = localStorage.getItem(userBalanceKey) || '0';
    const newBalance = Number(currentBalance) - requestData.amount;
    localStorage.setItem(userBalanceKey, newBalance.toString());
    setBalance(prev => prev - requestData.amount);

    const transaction = {
      userId: currentUser.id,
      username: currentUser.username,
      type: 'withdraw_request',
      amount: requestData.amount,
      method: requestData.method,
      requestId: result.key,
      date: new Date().toISOString(),
      status: 'pending'
    };
    
    await pushData('transactions', transaction);

    return { success: true, requestId: result.key };
  };

  const approveWithdraw = async (requestId, adminId) => {
    const request = withdrawRequests.find(r => r.id === requestId);
    if (!request) return { success: false, error: 'Заявка не найдена' };

    await updateData(`withdrawRequests/${requestId}`, {
      ...request,
      status: 'completed',
      confirmedBy: adminId,
      confirmedAt: new Date().toISOString()
    });

    const transaction = {
      userId: request.userId,
      username: request.username,
      type: 'withdraw',
      amount: request.amount,
      method: request.method,
      date: new Date().toISOString(),
      status: 'completed',
      requestId: requestId,
      confirmedBy: adminId
    };
    
    await pushData('transactions', transaction);

    return { success: true };
  };

  const rejectWithdraw = async (requestId, reason) => {
    const request = withdrawRequests.find(r => r.id === requestId);
    if (!request) return { success: false, error: 'Заявка не найдена' };

    const userBalanceKey = `visor_balance_${request.userId}`;
    const currentBalance = localStorage.getItem(userBalanceKey) || '0';
    const newBalance = Number(currentBalance) + request.amount;
    localStorage.setItem(userBalanceKey, newBalance.toString());

    if (currentUser?.id === request.userId) {
      setBalance(prev => prev + request.amount);
    }

    await updateData(`withdrawRequests/${requestId}`, {
      ...request,
      status: 'rejected',
      rejectReason: reason,
      rejectedAt: new Date().toISOString()
    });

    return { success: true };
  };

  // ===== ПОКУПКА =====
  const buyItem = async (item) => {
    if (!currentUser) {
      return { success: false, error: 'Пользователь не авторизован' };
    }

    const totalPrice = item.price;
    const commission = Math.floor(totalPrice * 0.05);
    const sellerGets = totalPrice - commission;

    if (balance < totalPrice) {
      return { success: false, error: 'Недостаточно средств' };
    }

    setBalance(prev => prev - totalPrice);
    setPlatformBalance(prev => prev + commission);

    const transaction = {
      userId: currentUser.id,
      username: currentUser.username,
      type: 'purchase',
      item: item.game,
      amount: item.amount,
      price: totalPrice,
      commission,
      seller: item.seller,
      sellerId: item.sellerId,
      date: new Date().toISOString(),
      status: 'completed'
    };
    
    await pushData('transactions', transaction);

    return { 
      success: true, 
      commission,
      sellerGets 
    };
  };

  const value = {
    balance,
    platformBalance,
    transactions,
    sbpPayments,
    withdrawRequests,
    deposit,
    depositForUser,
    createSbpPayment,
    approveSbpPayment,
    rejectSbpPayment,
    getAllSbpPayments,
    getUserSbpPayments,
    createWithdrawRequest,
    approveWithdraw,
    rejectWithdraw,
    buyItem
  };

  return (
    <BalanceContext.Provider value={value}>
      {children}
    </BalanceContext.Provider>
  );
}