// Ссылки на основные узлы базы данных
export const usersRef = ref(database, 'users');
export const listingsRef = ref(database, 'listings');
export const reviewsRef = ref(database, 'reviews');
export const gamesRef = ref(database, 'games');
export const categoriesRef = ref(database, 'categories');
export const chatsRef = ref(database, 'chats');
export const sbpPaymentsRef = ref(database, 'sbpPayments');
export const transactionsRef = ref(database, 'transactions');
export const supportTicketsRef = ref(database, 'supportTickets');
export const blockedUsersRef = ref(database, 'blockedUsers');
export const withdrawRequestsRef = ref(database, 'withdrawRequests');

// Функции для работы с Storage
export const uploadGameImage = async (gameId, file) => {
  try {
    const imageRef = storageRef(storage, `games/${gameId}/${file.name}`);
    await uploadBytes(imageRef, file);
    const downloadURL = await getDownloadURL(imageRef);
    return { success: true, url: downloadURL };
  } catch (error) {
    console.error('Ошибка загрузки изображения:', error);
    return { success: false, error: error.message };
  }
};

export const deleteGameImage = async (imagePath) => {
  try {
    const imageRef = storageRef(storage, imagePath);
    await deleteObject(imageRef);
    return { success: true };
  } catch (error) {
    console.error('Ошибка удаления изображения:', error);
    return { success: false, error: error.message };
  }
};

// Вспомогательные функции для базы данных
export const getRef = (path) => ref(database, path);
export const setData = (path, data) => set(ref(database, path), data);
export const pushData = (path, data) => push(ref(database, path), data);
export const updateData = (path, data) => update(ref(database, path), data);
export const removeData = (path) => remove(ref(database, path));
export const getData = (path) => get(ref(database, path));

export const onDataChange = (path, callback) => {
  const dbRef = ref(database, path);
  return onValue(dbRef, (snapshot) => {
    callback(snapshot.val());
  }, (error) => {
    console.error(`❌ Ошибка подписки на ${path}:`, error);
  });
};

export default database;