import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import { useNotification } from '../components/Notification';
import SupportChat from '../components/SupportChat';

function Support() {
  const navigate = useNavigate();
  const { 
    currentUser, 
    isSupport, 
    getAllSupportTickets, 
    users,
    createSupportTicket,
    blockUser,
    unblockUser,
    refundTransaction
  } = useUser();
  const { showNotification } = useNotification();
  
  const [selectedTicket, setSelectedTicket] = useState(null);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [showBlockModal, setShowBlockModal] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [blockReason, setBlockReason] = useState('');
  const [showRefundModal, setShowRefundModal] = useState(false);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [refundReason, setRefundReason] = useState('');
  const [showNewTicketModal, setShowNewTicketModal] = useState(false);
  const [newTicketForm, setNewTicketForm] = useState({
    type: 'question',
    description: ''
  });
  const [filter, setFilter] = useState('all'); // all, open, closed

  useEffect(() => {
    if (!currentUser) {
      navigate('/login');
    }
  }, [currentUser, navigate]);

  // Функция для обработки возврата
  const handleRefund = async () => {
    if (!refundReason.trim()) {
      showNotification('Укажите причину возврата', 'error');
      return;
    }

    const result = await refundTransaction(selectedTransaction.id, refundReason);
    if (result.success) {
      showNotification('Заявка на возврат создана', 'success');
      setShowRefundModal(false);
      setSelectedTransaction(null);
      setRefundReason('');
    }
  };

  if (!currentUser) return null;

  const tickets = getAllSupportTickets ? getAllSupportTickets() : [];
  
  // Для поддержки показываем все тикеты, для пользователей только свои
  const displayTickets = isSupport() ? tickets : tickets.filter(t => t.userId === currentUser.id);
  
  // Фильтрация по статусу
  const filteredTickets = displayTickets.filter(ticket => {
    if (filter === 'open') return ticket.status === 'open';
    if (filter === 'closed') return ticket.status === 'closed';
    return true;
  });

  const handleOpenTicket = (ticket) => {
    setSelectedTicket(ticket);
    setIsChatOpen(true);
  };

  const handleCreateTicket = async () => {
    if (!newTicketForm.description.trim()) {
      showNotification('Опишите вашу проблему', 'error');
      return;
    }

    const result = await createSupportTicket({
      type: newTicketForm.type,
      description: newTicketForm.description,
      status: 'open'
    });

    if (result.success) {
      showNotification('Обращение создано', 'success');
      setShowNewTicketModal(false);
      setNewTicketForm({ type: 'question', description: '' });
    }
  };

  const handleBlockUser = async () => {
    if (!blockReason.trim()) {
      showNotification('Укажите причину блокировки', 'error');
      return;
    }

    const result = await blockUser(selectedUser.id, blockReason);
    if (result.success) {
      showNotification(`Пользователь ${selectedUser.username} заблокирован`, 'success');
      setShowBlockModal(false);
      setSelectedUser(null);
      setBlockReason('');
    }
  };

  const handleUnblockUser = async (userId) => {
    if (window.confirm('Разблокировать пользователя?')) {
      await unblockUser(userId);
      showNotification('Пользователь разблокирован', 'success');
    }
  };

  const getSenderName = (ticket) => {
    const user = users.find(u => u.id === ticket.userId);
    return user ? user.username : 'Неизвестный пользователь';
  };

  return (
    <div>
      <h1 className="section-title">
        {isSupport() ? 'Панель поддержки' : 'Поддержка'}
      </h1>
      
      {/* Кнопка нового обращения для обычных пользователей */}
      {!isSupport() && (
        <div style={{ marginBottom: '2rem', textAlign: 'center' }}>
          <button
            className="btn btn-primary"
            onClick={() => setShowNewTicketModal(true)}
            style={{ width: 'auto' }}
          >
            📝 Создать обращение
          </button>
        </div>
      )}

      {/* Фильтры для поддержки */}
      {isSupport() && (
        <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem' }}>
          <button
            className={`btn ${filter === 'all' ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setFilter('all')}
            style={{ width: 'auto' }}
          >
            Все ({displayTickets.length})
          </button>
          <button
            className={`btn ${filter === 'open' ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setFilter('open')}
            style={{ width: 'auto' }}
          >
            Открытые ({displayTickets.filter(t => t.status === 'open').length})
          </button>
          <button
            className={`btn ${filter === 'closed' ? 'btn-primary' : 'btn-outline'}`}
            onClick={() => setFilter('closed')}
            style={{ width: 'auto' }}
          >
            Закрытые ({displayTickets.filter(t => t.status === 'closed').length})
          </button>
        </div>
      )}

      {/* Список тикетов */}
      <div style={{ marginTop: '1rem' }}>
        {filteredTickets.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
            <p>Нет обращений</p>
            {!isSupport() && (
              <button
                className="btn btn-outline"
                onClick={() => setShowNewTicketModal(true)}
                style={{ marginTop: '1rem' }}
              >
                Создать обращение
              </button>
            )}
          </div>
        ) : (
          filteredTickets.map(ticket => {
            const lastMessage = ticket.messages?.[ticket.messages.length - 1];
            const unread = isSupport() 
              ? lastMessage?.from !== currentUser.id && ticket.status === 'open'
              : lastMessage?.from !== currentUser.id && !ticket.isRead;
            
            return (
              <div 
                key={ticket.id} 
                className="listing-card" 
                style={{ 
                  marginBottom: '1rem',
                  cursor: 'pointer',
                  borderLeft: ticket.status === 'open' ? '4px solid var(--warning)' : '4px solid var(--success)',
                  background: unread ? '#f0f4ff' : 'white'
                }}
                onClick={() => handleOpenTicket(ticket)}
              >
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
                      <h3 style={{ margin: 0 }}>
                        {ticket.type === 'block' && '🚫 Блокировка'}
                        {ticket.type === 'refund' && '💰 Возврат'}
                        {ticket.type === 'question' && '❓ Вопрос'}
                        {!ticket.type && '📨 Обращение'}
                      </h3>
                      {unread && (
                        <span style={{
                          background: 'var(--primary)',
                          color: 'white',
                          borderRadius: '12px',
                          padding: '2px 8px',
                          fontSize: '0.7rem',
                          fontWeight: 'bold'
                        }}>
                          NEW
                        </span>
                      )}
                    </div>
                    
                    {isSupport() && (
                      <div style={{ fontSize: '0.9rem', color: 'var(--primary)', marginBottom: '0.25rem' }}>
                        От: {getSenderName(ticket)}
                      </div>
                    )}
                    
                    <div style={{ marginBottom: '0.5rem' }}>
                      {ticket.description}
                    </div>
                    
                    <div style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>
                      {new Date(ticket.createdAt).toLocaleString()} • 
                      Сообщений: {ticket.messages?.length || 0}
                      {ticket.status === 'closed' && ' • Закрыто'}
                    </div>
                  </div>
                  <div style={{ fontSize: '1.5rem', color: 'var(--primary)' }}>
                    →
                  </div>
                </div>
              </div>
            );
          })
        )}
      </div>

      {/* Модалка чата */}
      {selectedTicket && (
        <SupportChat
          isOpen={isChatOpen}
          onClose={() => {
            setIsChatOpen(false);
            setSelectedTicket(null);
          }}
          ticket={selectedTicket}
        />
      )}

      {/* Модалка нового обращения */}
      {showNewTicketModal && (
        <div className="modal-overlay" onClick={() => setShowNewTicketModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <span className="modal-close" onClick={() => setShowNewTicketModal(false)}>&times;</span>
            <h2>Новое обращение</h2>
            
            <div className="form-group">
              <label>Тип обращения</label>
              <select
                value={newTicketForm.type}
                onChange={(e) => setNewTicketForm({ ...newTicketForm, type: e.target.value })}
                className="search-select"
              >
                <option value="question">❓ Вопрос</option>
                <option value="refund">💰 Возврат</option>
                <option value="complaint">⚠️ Жалоба</option>
              </select>
            </div>

            <div className="form-group">
              <label>Описание</label>
              <textarea
                rows="4"
                value={newTicketForm.description}
                onChange={(e) => setNewTicketForm({ ...newTicketForm, description: e.target.value })}
                placeholder="Опишите вашу проблему подробно..."
                style={{ width: '100%', padding: '0.75rem' }}
              />
            </div>

            <div style={{ display: 'flex', gap: '1rem' }}>
              <button 
                className="btn btn-outline" 
                onClick={() => setShowNewTicketModal(false)}
                style={{ flex: 1 }}
              >
                Отмена
              </button>
              <button 
                className="btn btn-primary" 
                onClick={handleCreateTicket}
                style={{ flex: 2 }}
              >
                Отправить
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Модалка блокировки (только для поддержки) */}
      {showBlockModal && isSupport() && (
        <div className="modal-overlay" onClick={() => setShowBlockModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <span className="modal-close" onClick={() => setShowBlockModal(false)}>&times;</span>
            <h2>Блокировка пользователя</h2>
            
            <p style={{ marginBottom: '1rem' }}>
              Заблокировать <strong>{selectedUser?.username}</strong>?
            </p>

            <div className="form-group">
              <label>Причина блокировки</label>
              <textarea
                rows="3"
                value={blockReason}
                onChange={(e) => setBlockReason(e.target.value)}
                placeholder="Укажите причину блокировки..."
                style={{ width: '100%', padding: '0.75rem' }}
              />
            </div>

            <div style={{ display: 'flex', gap: '1rem' }}>
              <button 
                className="btn btn-outline" 
                onClick={() => setShowBlockModal(false)}
                style={{ flex: 1 }}
              >
                Отмена
              </button>
              <button 
                className="btn btn-danger" 
                onClick={handleBlockUser}
                style={{ flex: 2 }}
              >
                Заблокировать
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Модалка возврата (только для поддержки) */}
      {showRefundModal && isSupport() && (
        <div className="modal-overlay" onClick={() => setShowRefundModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <span className="modal-close" onClick={() => setShowRefundModal(false)}>&times;</span>
            <h2>Возврат средств</h2>
            
            <p style={{ marginBottom: '1rem' }}>
              Возврат по транзакции на сумму <strong>{selectedTransaction?.amount || selectedTransaction?.price} ₽</strong>
            </p>

            <div className="form-group">
              <label>Причина возврата</label>
              <textarea
                rows="3"
                value={refundReason}
                onChange={(e) => setRefundReason(e.target.value)}
                placeholder="Укажите причину возврата..."
                style={{ width: '100%', padding: '0.75rem' }}
              />
            </div>

            <div style={{ display: 'flex', gap: '1rem' }}>
              <button 
                className="btn btn-outline" 
                onClick={() => setShowRefundModal(false)}
                style={{ flex: 1 }}
              >
                Отмена
              </button>
              <button 
                className="btn btn-primary" 
                onClick={handleRefund}
                style={{ flex: 2 }}
              >
                Создать заявку
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Support;