import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import { useNotification } from '../components/Notification';

function Sell() {
  const { createListing, getGames, getCategoriesByGame, currentUser } = useUser();
  const { showNotification } = useNotification();
  const navigate = useNavigate();
  
  const [formData, setFormData] = useState({
    game: '',
    category: '',
    amount: '',
    currency: '',
    price: ''
  });

  const [gamesList, setGamesList] = useState([]);
  const [selectedGameCategories, setSelectedGameCategories] = useState([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Загружаем список игр
  useEffect(() => {
    setGamesList(getGames());
  }, [getGames]);

  // Обновляем категории при выборе игры
  useEffect(() => {
    if (formData.game) {
      const selectedGame = gamesList.find(g => g.name === formData.game);
      if (selectedGame) {
        const cats = getCategoriesByGame(selectedGame.id);
        setSelectedGameCategories(cats);
      } else {
        setSelectedGameCategories([]);
      }
    } else {
      setSelectedGameCategories([]);
    }
  }, [formData.game, gamesList, getCategoriesByGame]);

  // Проверка авторизации
  useEffect(() => {
    if (!currentUser) {
      showNotification('Сначала войдите в систему', 'error');
      navigate('/login');
    }
  }, [currentUser, navigate, showNotification]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (isSubmitting) return;
    setIsSubmitting(true);

    // Валидация
    if (!formData.game || !formData.amount || !formData.currency || !formData.price) {
      showNotification('Заполните все поля', 'error');
      setIsSubmitting(false);
      return;
    }

    const amount = Number(formData.amount);
    const price = Number(formData.price);

    if (amount <= 0) {
      showNotification('Количество должно быть больше 0', 'error');
      setIsSubmitting(false);
      return;
    }

    if (price <= 0) {
      showNotification('Цена должна быть больше 0', 'error');
      setIsSubmitting(false);
      return;
    }

    // Создаем объявление
    const listing = {
      game: formData.game,
      category: formData.category || null,
      type: 'sell',
      amount: amount,
      currency: formData.currency,
      price: price,
      seller: currentUser.username,
      sellerId: currentUser.id
    };

    const result = await createListing(listing);
    
    if (result.success) {
      showNotification('✅ Ваше объявление успешно опубликовано!', 'success', 4000);
      
      // Очищаем форму
      setFormData({
        game: '',
        category: '',
        amount: '',
        currency: '',
        price: ''
      });
      
      // Закрываем окно через секунду
      setTimeout(() => {
        navigate('/listings');
      }, 1500);
    } else {
      showNotification(result.error || 'Ошибка при создании объявления', 'error');
      setIsSubmitting(false);
    }
  };

  // Расчет комиссии
  const commission = formData.price ? Math.floor(formData.price * 0.05) : 0;
  const youGet = formData.price ? formData.price - commission : 0;

  if (!currentUser) {
    return null;
  }

  return (
    <div className="form-container">
      <h1 className="form-title">Продать игровую валюту</h1>
      
      <form onSubmit={handleSubmit}>
        {/* Выбор игры */}
        <div className="form-group">
          <label>Игра *</label>
          <select
            name="game"
            value={formData.game}
            onChange={handleChange}
            required
          >
            <option value="">Выберите игру</option>
            {gamesList.map(game => (
              <option key={game.id} value={game.name}>{game.name}</option>
            ))}
          </select>
        </div>

        {/* Выбор подкатегории */}
        {selectedGameCategories.length > 0 && (
          <div className="form-group">
            <label>Подкатегория</label>
            <select
              name="category"
              value={formData.category}
              onChange={handleChange}
            >
              <option value="">Без категории</option>
              {selectedGameCategories.map(cat => (
                <option key={cat.id} value={cat.name}>{cat.name}</option>
              ))}
            </select>
          </div>
        )}

        {/* Количество */}
        <div className="form-group">
          <label>Количество *</label>
          <input
            type="number"
            name="amount"
            value={formData.amount}
            onChange={handleChange}
            placeholder="Например: 10000"
            min="1"
            required
          />
        </div>

        {/* Валюта */}
        <div className="form-group">
          <label>Валюта в игре *</label>
          <input
            type="text"
            name="currency"
            value={formData.currency}
            onChange={handleChange}
            placeholder="Например: gold, MMR, V-Bucks"
            required
          />
        </div>

        {/* Цена */}
        <div className="form-group">
          <label>Цена (₽) *</label>
          <input
            type="number"
            name="price"
            value={formData.price}
            onChange={handleChange}
            placeholder="Например: 450"
            min="1"
            required
          />
        </div>

        {/* Информация о комиссии */}
        {formData.price && (
          <div style={{ 
            background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
            color: 'white',
            padding: '1rem', 
            borderRadius: '8px',
            marginBottom: '1.5rem'
          }}>
            <p>💰 Комиссия платформы (5%): {commission} ₽</p>
            <p>💵 Вы получите: {youGet} ₽</p>
            <p>🏦 После продажи средства поступят на ваш баланс</p>
          </div>
        )}

        {/* Кнопка */}
        <button 
          type="submit" 
          className="btn btn-primary" 
          disabled={isSubmitting}
        >
          {isSubmitting ? 'Публикация...' : 'Опубликовать объявление'}
        </button>
      </form>

      {/* Подсказки */}
      <div style={{ marginTop: '2rem', fontSize: '0.9rem', color: 'var(--gray)' }}>
        <p>⚠️ После продажи средства поступят на ваш баланс</p>
        <p>⚠️ Вывод средств возможен после подтверждения сделки</p>
        <p>⚠️ Комиссия платформы: 5%</p>
      </div>
    </div>
  );
}

export default Sell;