import React, { useState } from 'react';
import { usePayment } from '../context/PaymentContext';
import { useUser } from '../context/UserContext';
import { useBalance } from '../context/BalanceContext';
import { useNotification } from './Notification';

function YooMoneyModal({ isOpen, onClose }) {
  const { createPayment, loading } = usePayment();
  const { currentUser } = useUser();
  const { deposit } = useBalance();
  const { showNotification } = useNotification();
  
  const [amount, setAmount] = useState('');
  const [step, setStep] = useState(1); // 1: ввод суммы, 2: выбор способа оплаты

  const paymentMethods = [
    {
      id: 'card',
      name: 'Банковская карта',
      icon: '💳',
      description: 'Visa, Mastercard, МИР',
      minAmount: 10,
      maxAmount: 15000
    },
    {
      id: 'yoomoney',
      name: 'ЮMoney',
      icon: '💰',
      description: 'С баланса кошелька',
      minAmount: 1,
      maxAmount: 15000
    }
  ];

  const [selectedMethod, setSelectedMethod] = useState('card');

  const handleAmountSubmit = async (e) => {
    e.preventDefault();
    
    const method = paymentMethods.find(m => m.id === selectedMethod);
    const numAmount = Number(amount);

    // Валидация
    if (numAmount < method.minAmount) {
      showNotification(`Минимальная сумма ${method.minAmount} ₽`, 'error');
      return;
    }
    if (numAmount > method.maxAmount) {
      showNotification(`Максимальная сумма ${method.maxAmount} ₽`, 'error');
      return;
    }

    // Создаем описание платежа
    const description = `Пополнение баланса Visor Market на ${numAmount} ₽`;
    
    // Создаем платеж через ЮMoney
    const result = createPayment(numAmount, description);
    
    if (result.success) {
      // Перенаправляем пользователя на страницу оплаты ЮMoney
      window.location.href = result.paymentUrl;
    } else {
      showNotification(result.error, 'error');
    }
  };

  const handleClose = () => {
    onClose();
    setStep(1);
    setAmount('');
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={handleClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <span className="modal-close" onClick={handleClose}>&times;</span>
        
        {/* ШАГ 1: Выбор суммы и способа */}
        {step === 1 && (
          <>
            <h2>Пополнение баланса</h2>
            
            {/* Выбор способа оплаты */}
            <div style={{ marginBottom: '1.5rem' }}>
              <label>Способ оплаты</label>
              <div style={{ display: 'grid', gap: '0.5rem', marginTop: '0.5rem' }}>
                {paymentMethods.map(method => (
                  <div
                    key={method.id}
                    onClick={() => setSelectedMethod(method.id)}
                    style={{
                      padding: '1rem',
                      border: `2px solid ${selectedMethod === method.id ? 'var(--primary)' : '#e5e7eb'}`,
                      borderRadius: '8px',
                      cursor: 'pointer',
                      transition: 'all 0.3s',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '1rem'
                    }}
                  >
                    <div style={{ fontSize: '2rem' }}>{method.icon}</div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 'bold' }}>{method.name}</div>
                      <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>{method.description}</div>
                    </div>
                    {selectedMethod === method.id && (
                      <span style={{ color: 'var(--primary)', fontSize: '1.2rem' }}>✓</span>
                    )}
                  </div>
                ))}
              </div>
            </div>

            <form onSubmit={handleAmountSubmit}>
              <div className="form-group">
                <label>Сумма пополнения (₽)</label>
                <input
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  placeholder="Введите сумму"
                  step="1"
                  min={paymentMethods.find(m => m.id === selectedMethod)?.minAmount}
                  required
                  autoFocus
                />
                <small>
                  Мин. {paymentMethods.find(m => m.id === selectedMethod)?.minAmount} ₽, 
                  макс. {paymentMethods.find(m => m.id === selectedMethod)?.maxAmount} ₽
                </small>
              </div>
              
              <button 
                type="submit" 
                className="btn btn-primary" 
                disabled={loading}
              >
                {loading ? 'Создание платежа...' : 'Продолжить'}
              </button>
            </form>

            {/* Информация о ЮMoney */}
            <div style={{ 
              marginTop: '1.5rem', 
              padding: '1rem', 
              background: '#e3f2fd', 
              borderRadius: '8px',
              fontSize: '0.9rem'
            }}>
              <p style={{ margin: 0, fontWeight: 'bold' }}>ℹ️ Как это работает?</p>
              <ol style={{ marginTop: '0.5rem', paddingLeft: '1.2rem', color: 'var(--gray)' }}>
                <li>Вы вводите сумму и нажимаете "Продолжить"</li>
                <li>Мы перенаправляем вас на защищенную страницу ЮMoney</li>
                <li>Вы оплачиваете удобным способом (карта или кошелек)</li>
                <li>Баланс пополняется автоматически в течение нескольких секунд</li>
              </ol>
              <p style={{ marginTop: '0.5rem', fontSize: '0.8rem', color: 'var(--gray)' }}>
                ⚠️ При оплате картой взимается комиссия 3%
              </p>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default YooMoneyModal;