import React, { useState } from 'react';
import { useUser } from '../context/UserContext';
import { useNotification } from './Notification';

function ReviewModal({ isOpen, onClose, sellerId, sellerName, transactionId }) {
  const { addReview, currentUser } = useUser();
  const { showNotification } = useNotification();
  
  const [rating, setRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [comment, setComment] = useState('');
  const [submitting, setSubmitting] = useState(false);

  if (!isOpen || !currentUser) return null;

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (rating === 0) {
      showNotification('Пожалуйста, поставьте оценку', 'error');
      return;
    }

    if (!comment.trim()) {
      showNotification('Пожалуйста, напишите отзыв', 'error');
      return;
    }

    setSubmitting(true);

    const result = addReview({
      fromUserId: currentUser.id,
      toUserId: sellerId,
      transactionId: transactionId,
      rating: rating,
      comment: comment.trim()
    });

    if (result.success) {
      showNotification('Отзыв оставлен! Спасибо!', 'success');
      onClose();
    } else {
      showNotification(result.error, 'error');
    }

    setSubmitting(false);
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e => e.stopPropagation()}>
        <span className="modal-close" onClick={onClose}>&times;</span>
        
        <h2>Оставить отзыв о {sellerName}</h2>
        
        <form onSubmit={handleSubmit}>
          {/* Звездный рейтинг */}
          <div className="form-group">
            <label>Оценка *</label>
            <div style={{ 
              display: 'flex', 
              gap: '0.5rem',
              fontSize: '2rem',
              cursor: 'pointer'
            }}>
              {[1, 2, 3, 4, 5].map(star => (
                <span
                  key={star}
                  onMouseEnter={() => setHoverRating(star)}
                  onMouseLeave={() => setHoverRating(0)}
                  onClick={() => setRating(star)}
                  style={{
                    color: star <= (hoverRating || rating) ? '#ffc107' : '#e4e5e9',
                    transition: 'color 0.2s'
                  }}
                >
                  ★
                </span>
              ))}
            </div>
            <small>
              {rating === 1 && '👎 Очень плохо'}
              {rating === 2 && '😕 Плохо'}
              {rating === 3 && '😐 Нормально'}
              {rating === 4 && '👍 Хорошо'}
              {rating === 5 && '🌟 Отлично!'}
            </small>
          </div>

          {/* Комментарий */}
          <div className="form-group">
            <label>Комментарий *</label>
            <textarea
              rows="4"
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              placeholder="Напишите подробно о сделке..."
              maxLength="500"
              required
            />
            <small>{comment.length}/500 символов</small>
          </div>

          {/* Предупреждение */}
          <div style={{
            background: '#fff3cd',
            color: '#856404',
            padding: '0.75rem',
            borderRadius: '8px',
            marginBottom: '1.5rem',
            fontSize: '0.9rem'
          }}>
            ⚠️ Отзыв нельзя будет удалить или изменить. Только администрация может удалить отзыв в случае нарушения правил.
          </div>

          {/* Кнопки */}
          <div style={{ display: 'flex', gap: '1rem' }}>
            <button 
              type="button"
              className="btn btn-outline" 
              onClick={onClose}
              disabled={submitting}
              style={{ flex: 1 }}
            >
              Отмена
            </button>
            <button 
              type="submit"
              className="btn btn-primary" 
              disabled={submitting}
              style={{ flex: 2 }}
            >
              {submitting ? 'Отправка...' : 'Оставить отзыв'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default ReviewModal;