import React, { createContext, useState, useContext } from 'react';
import { useUser } from './UserContext';
import { useBalance } from './BalanceContext';

const PaymentContext = createContext();

export function usePayment() {
  return useContext(PaymentContext);
}

export function PaymentProvider({ children }) {
  const { currentUser } = useUser();
  const { deposit } = useBalance();
  const [loading, setLoading] = useState(false);

  // Конфигурация ЮMoney
  const YOOMONEY_CONFIG = {
    walletId: process.env.REACT_APP_YOOMONEY_WALLET_ID, // Номер кошелька
    notificationUrl: process.env.REACT_APP_YOOMONEY_NOTIFICATION_URL, // URL для уведомлений
    successUrl: process.env.REACT_APP_YOOMONEY_SUCCESS_URL || window.location.origin + '/#/profile',
  };

  /**
   * Создание платежа через ЮMoney
   * @param {number} amount - Сумма в рублях
   * @param {string} description - Описание платежа
   */
  const createPayment = (amount, description = 'Пополнение баланса Visor Market') => {
    if (!currentUser) {
      return { success: false, error: 'Пользователь не авторизован' };
    }

    setLoading(true);

    try {
      // Генерируем уникальный идентификатор платежа (label)
      const label = `visor_${currentUser.id}_${Date.now()}`;

      // Формируем URL для редиректа на ЮMoney
      const formData = new URLSearchParams();
      formData.append('receiver', YOOMONEY_CONFIG.walletId);
      formData.append('quickpay-form', 'button');
      formData.append('paymentType', 'AC'); // AC - банковская карта
      formData.append('sum', amount.toFixed(2));
      formData.append('label', label);
      formData.append('comment', description);
      formData.append('successURL', YOOMONEY_CONFIG.successUrl);

      const paymentUrl = `https://yoomoney.ru/quickpay/confirm.xml?${formData.toString()}`;

      return {
        success: true,
        paymentUrl: paymentUrl,
        label: label
      };

    } catch (error) {
      console.error('Ошибка создания платежа:', error);
      return {
        success: false,
        error: error.message || 'Ошибка при создании платежа'
      };
    } finally {
      setLoading(false);
    }
  };

  const value = {
    createPayment,
    loading
  };

  return (
    <PaymentContext.Provider value={value}>
      {children}
    </PaymentContext.Provider>
  );
}