import React, { createContext, useState, useContext, useEffect } from 'react';
import { 
  usersRef, 
  listingsRef, 
  reviewsRef, 
  gamesRef, 
  categoriesRef,
  chatsRef,
  supportTicketsRef,
  blockedUsersRef,
  onDataChange,
  pushData,
  updateData,
  removeData,
  getData,
  uploadGameImage,
  deleteGameImage
} from '../firebase';

const UserContext = createContext();

export function useUser() {
  return useContext(UserContext);
}

export function UserProvider({ children }) {
  const [currentUser, setCurrentUser] = useState(null);
  const [users, setUsers] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [games, setGames] = useState([]);
  const [categories, setCategories] = useState([]);
  const [allListings, setAllListings] = useState([]);
  const [chats, setChats] = useState([]);
  const [supportTickets, setSupportTickets] = useState([]);
  const [blockedUsers, setBlockedUsers] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [unreadSupportCount, setUnreadSupportCount] = useState(0);
  const [loading, setLoading] = useState(true);

  // ===== ПОДПИСКА НА ИЗМЕНЕНИЯ В БАЗЕ ДАННЫХ =====
  useEffect(() => {
    // Подписка на пользователей
    const unsubscribeUsers = onDataChange('users', (data) => {
      if (data) {
        const usersArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setUsers(usersArray);
      } else {
        setUsers([]);
      }
    });

    // Подписка на игры
    const unsubscribeGames = onDataChange('games', (data) => {
      if (data) {
        const gamesArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setGames(gamesArray);
      } else {
        setGames([]);
      }
    });

    // Подписка на подкатегории
    const unsubscribeCategories = onDataChange('categories', (data) => {
      if (data) {
        const categoriesArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setCategories(categoriesArray);
      } else {
        setCategories([]);
      }
    });

    // Подписка на объявления
    const unsubscribeListings = onDataChange('listings', (data) => {
      if (data) {
        const listingsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setAllListings(listingsArray);
      } else {
        setAllListings([]);
      }
      setLoading(false);
    });

    // Подписка на отзывы
    const unsubscribeReviews = onDataChange('reviews', (data) => {
      if (data) {
        const reviewsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setReviews(reviewsArray);
      } else {
        setReviews([]);
      }
    });

    // Подписка на чаты
    const unsubscribeChats = onDataChange('chats', (data) => {
      if (data) {
        const chatsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setChats(chatsArray);
      } else {
        setChats([]);
      }
    });

    // Подписка на тикеты поддержки
    const unsubscribeTickets = onDataChange('supportTickets', (data) => {
      if (data) {
        const ticketsArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setSupportTickets(ticketsArray);
      } else {
        setSupportTickets([]);
      }
    });

    // Подписка на заблокированных пользователей
    const unsubscribeBlocked = onDataChange('blockedUsers', (data) => {
      if (data) {
        const blockedArray = Object.keys(data).map(key => ({
          id: key,
          ...data[key]
        }));
        setBlockedUsers(blockedArray);
      } else {
        setBlockedUsers([]);
      }
    });

    // Загружаем текущего пользователя из localStorage
    const savedUser = localStorage.getItem('visor_current_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }

    // Отписка при размонтировании
    return () => {
      unsubscribeUsers();
      unsubscribeGames();
      unsubscribeCategories();
      unsubscribeListings();
      unsubscribeReviews();
      unsubscribeChats();
      unsubscribeTickets();
      unsubscribeBlocked();
    };
  }, []);

  // Подсчет непрочитанных сообщений в чатах
  useEffect(() => {
    if (!currentUser) return;
    
    const unread = chats.reduce((count, chat) => {
      const unreadInChat = chat.messages?.filter(m => 
        !m.read && m.toUserId === currentUser.id
      ).length || 0;
      return count + unreadInChat;
    }, 0);
    
    setUnreadCount(unread);
  }, [chats, currentUser]);

  // Подсчет непрочитанных тикетов поддержки
  useEffect(() => {
    if (!currentUser) return;
    
    const unread = supportTickets.filter(ticket => {
      if (currentUser.role === 'admin' || currentUser.role === 'support') {
        const lastMessage = ticket.messages?.[ticket.messages.length - 1];
        return ticket.status === 'open' && lastMessage?.from !== currentUser.id;
      }
      if (ticket.userId === currentUser.id) {
        const lastMessage = ticket.messages?.[ticket.messages.length - 1];
        return lastMessage?.from !== currentUser.id && !ticket.isRead;
      }
      return false;
    }).length;
    
    setUnreadSupportCount(unread);
  }, [supportTickets, currentUser]);

  // ===== ПРОВЕРКА РОЛЕЙ =====
  const isAdmin = () => {
    return currentUser?.role === 'admin' || currentUser?.telegramId === 802498337;
  };

  const isSupport = () => {
    return currentUser?.role === 'support' || currentUser?.role === 'admin';
  };

  const isBlocked = (userId) => {
    return blockedUsers.some(b => b.userId === userId && b.active);
  };

  // ===== ВХОД ЧЕРЕЗ TELEGRAM =====
  const loginWithTelegram = async (telegramData) => {
    const blocked = blockedUsers.find(b => b.telegramId === telegramData.id && b.active);
    if (blocked) {
      return { success: false, error: 'Ваш аккаунт заблокирован. Обратитесь в поддержку.' };
    }

    const existingUser = users.find(u => u.telegramId === telegramData.id);
    
    if (existingUser) {
      setCurrentUser(existingUser);
      localStorage.setItem('visor_current_user', JSON.stringify(existingUser));
      return { success: true, user: existingUser };
    }

    const newUser = {
      telegramId: telegramData.id,
      username: telegramData.username || `user_${telegramData.id}`,
      firstName: telegramData.first_name || '',
      lastName: telegramData.last_name || '',
      photoUrl: telegramData.photo_url || '',
      authDate: telegramData.auth_date,
      registrationDate: new Date().toISOString(),
      role: telegramData.id === 802498337 ? 'admin' : 'user',
      stats: {
        totalTrades: 0,
        positiveReviews: 0,
        negativeReviews: 0,
        avgRating: 0
      }
    };

    const result = await pushData('users', newUser);
    const userId = result.key;
    const userWithId = { id: userId, ...newUser };
    
    setCurrentUser(userWithId);
    localStorage.setItem('visor_current_user', JSON.stringify(userWithId));
    
    return { success: true, user: userWithId };
  };

  // ===== ВЫХОД =====
  const logout = () => {
    setCurrentUser(null);
    localStorage.removeItem('visor_current_user');
  };

  // ===== ОТЗЫВЫ =====
  const addReview = async (review) => {
    const existingReview = reviews.find(
      r => r.fromUserId === review.fromUserId && r.toUserId === review.toUserId
    );

    if (existingReview) {
      return { success: false, error: 'Вы уже оставляли отзыв этому пользователю' };
    }

    const newReview = {
      ...review,
      date: new Date().toISOString(),
      isDeleted: false
    };

    const result = await pushData('reviews', newReview);
    const reviewId = result.key;

    await updateUserStats(review.toUserId);

    return { success: true, review: { id: reviewId, ...newReview } };
  };

  const getUserReviews = (userId) => {
    return reviews
      .filter(r => r.toUserId === userId && !r.isDeleted)
      .sort((a, b) => new Date(b.date) - new Date(a.date));
  };

  const deleteReview = async (reviewId) => {
    await updateData(`reviews/${reviewId}`, { isDeleted: true });
    
    const review = reviews.find(r => r.id === reviewId);
    if (review) {
      await updateUserStats(review.toUserId);
    }
  };

  const updateUserStats = async (userId) => {
    const userReviews = reviews.filter(r => r.toUserId === userId && !r.isDeleted);
    
    const totalReviews = userReviews.length;
    const positiveCount = userReviews.filter(r => r.rating >= 4).length;
    const negativeCount = userReviews.filter(r => r.rating <= 2).length;
    const avgRating = totalReviews > 0 
      ? userReviews.reduce((sum, r) => sum + r.rating, 0) / totalReviews 
      : 0;

    const user = users.find(u => u.id === userId);
    if (user) {
      await updateData(`users/${userId}`, {
        ...user,
        stats: {
          totalTrades: user.stats?.totalTrades || 0,
          positiveReviews: positiveCount,
          negativeReviews: negativeCount,
          avgRating: avgRating
        }
      });
    }
  };

  // ===== УПРАВЛЕНИЕ ПОЛЬЗОВАТЕЛЯМИ =====
  const getAllUsers = () => users;

  const changeUserRole = async (userId, newRole) => {
    const user = users.find(u => u.id === userId);
    if (user) {
      await updateData(`users/${userId}`, { ...user, role: newRole });
    }
  };

  // ===== БЛОКИРОВКА ПОЛЬЗОВАТЕЛЕЙ =====
  const blockUser = async (userId, reason) => {
    const user = users.find(u => u.id === userId);
    if (!user) return { success: false, error: 'Пользователь не найден' };

    const blockData = {
      userId: user.id,
      telegramId: user.telegramId,
      username: user.username,
      reason: reason,
      blockedBy: currentUser?.id,
      blockedAt: new Date().toISOString(),
      active: true
    };

    await pushData('blockedUsers', blockData);
    
    await createSupportTicket({
      type: 'block',
      userId: user.id,
      description: `Пользователь заблокирован. Причина: ${reason}`,
      status: 'closed'
    });

    return { success: true };
  };

  const unblockUser = async (userId) => {
    const block = blockedUsers.find(b => b.userId === userId && b.active);
    if (block) {
      await updateData(`blockedUsers/${block.id}`, { ...block, active: false });
    }
    return { success: true };
  };

  // ===== ТИКЕТЫ ПОДДЕРЖКИ =====
  const createSupportTicket = async (ticketData) => {
    const newTicket = {
      ...ticketData,
      userId: ticketData.userId || currentUser?.id,
      username: ticketData.username || currentUser?.username,
      createdAt: new Date().toISOString(),
      status: ticketData.status || 'open',
      messages: ticketData.messages || [{
        from: currentUser?.id,
        text: ticketData.description,
        timestamp: new Date().toISOString()
      }],
      isRead: false
    };

    const result = await pushData('supportTickets', newTicket);
    return { success: true, ticketId: result.key };
  };

  const addTicketMessage = async (ticketId, message) => {
    const ticket = supportTickets.find(t => t.id === ticketId);
    if (!ticket) return { success: false, error: 'Тикет не найден' };

    const updatedMessages = [...(ticket.messages || []), {
      from: currentUser?.id,
      text: message,
      timestamp: new Date().toISOString()
    }];

    await updateData(`supportTickets/${ticketId}`, {
      ...ticket,
      messages: updatedMessages,
      isRead: false,
      updatedAt: new Date().toISOString()
    });

    return { success: true };
  };

  const closeSupportTicket = async (ticketId) => {
    const ticket = supportTickets.find(t => t.id === ticketId);
    if (!ticket) return { success: false, error: 'Тикет не найден' };

    await updateData(`supportTickets/${ticketId}`, {
      ...ticket,
      status: 'closed',
      closedAt: new Date().toISOString(),
      closedBy: currentUser?.id
    });

    return { success: true };
  };

  const getUserTickets = (userId) => {
    return supportTickets
      .filter(t => t.userId === userId)
      .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  };

  const getAllSupportTickets = () => {
    return supportTickets.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
  };

  // ===== ВОЗВРАТ ДЕНЕГ ЗА СДЕЛКУ =====
  const refundTransaction = async (transactionId, reason) => {
    await createSupportTicket({
      type: 'refund',
      userId: currentUser?.id,
      transactionId: transactionId,
      description: `Возврат средств по сделке ${transactionId}. Причина: ${reason}`,
      status: 'open'
    });

    return { success: true };
  };

  // ===== УПРАВЛЕНИЕ КАТЕГОРИЯМИ (ИГРАМИ) =====
  const getGames = () => games;

  const addGame = async (gameData, imageFile = null) => {
    let imageUrl = null;
    
    if (imageFile) {
      const uploadResult = await uploadGameImage('temp', imageFile);
      if (uploadResult.success) {
        imageUrl = uploadResult.url;
      }
    }

    const newGame = {
      ...gameData,
      imageUrl: imageUrl,
      listings: 0,
      minPrice: 0,
      active: true,
      createdAt: new Date().toISOString()
    };

    const result = await pushData('games', newGame);
    const gameId = result.key;

    // Если есть изображение, перемещаем его в папку с ID игры
    if (imageUrl && imageFile) {
      const newImageUrl = await uploadGameImage(gameId, imageFile);
      if (newImageUrl.success) {
        await updateData(`games/${gameId}`, { ...newGame, imageUrl: newImageUrl.url });
      }
    }

    return { id: gameId, ...newGame };
  };

  const updateGame = async (gameId, updates, imageFile = null) => {
    const game = games.find(g => g.id === gameId);
    if (!game) return;

    let imageUrl = game.imageUrl;

    if (imageFile) {
      const uploadResult = await uploadGameImage(gameId, imageFile);
      if (uploadResult.success) {
        imageUrl = uploadResult.url;
      }
    }

    await updateData(`games/${gameId}`, { ...game, ...updates, imageUrl });
  };

  const deleteGame = async (gameId) => {
    await removeData(`games/${gameId}`);
  };

  // ===== УПРАВЛЕНИЕ ПОДКАТЕГОРИЯМИ =====
  const getCategories = () => categories;

  const addCategory = async (categoryData) => {
    const newCategory = {
      ...categoryData,
      createdAt: new Date().toISOString()
    };
    const result = await pushData('categories', newCategory);
    return { id: result.key, ...newCategory };
  };

  const updateCategory = async (categoryId, updates) => {
    const category = categories.find(c => c.id === categoryId);
    if (category) {
      await updateData(`categories/${categoryId}`, { ...category, ...updates });
    }
  };

  const deleteCategory = async (categoryId) => {
    await removeData(`categories/${categoryId}`);
  };

  const getCategoriesByGame = (gameId) => {
    return categories.filter(c => c.gameId === gameId);
  };

  // ===== УПРАВЛЕНИЕ ОБЪЯВЛЕНИЯМИ =====
  const getAllListings = () => allListings;

  const createListing = async (listing) => {
    if (currentUser && isBlocked(currentUser.id)) {
      return { success: false, error: 'Ваш аккаунт заблокирован. Вы не можете создавать объявления.' };
    }

    const newListing = {
      ...listing,
      date: new Date().toISOString(),
      status: 'active'
    };
    
    const result = await pushData('listings', newListing);
    const listingId = result.key;
    
    await updateGameListingsCount(listing.game);
    
    return { success: true, listing: { id: listingId, ...newListing } };
  };

  const deleteListing = async (listingId) => {
    const listing = allListings.find(l => l.id === listingId);
    await removeData(`listings/${listingId}`);
    
    if (listing) {
      await updateGameListingsCount(listing.game);
    }
  };

  const completeListing = async (listingId) => {
    const listing = allListings.find(l => l.id === listingId);
    if (listing) {
      await updateData(`listings/${listingId}`, { ...listing, status: 'completed' });
      
      const seller = users.find(u => u.username === listing.seller);
      if (seller) {
        await updateUserStats(seller.id);
      }
      await updateGameListingsCount(listing.game);
    }
  };

  const updateGameListingsCount = async (gameName) => {
    const activeListingsForGame = allListings.filter(
      l => l.game === gameName && l.status === 'active'
    ).length;
    
    const minPrice = allListings
      .filter(l => l.game === gameName && l.status === 'active')
      .reduce((min, l) => Math.min(min, l.price / l.amount), Infinity);
    
    const game = games.find(g => g.name === gameName);
    if (game) {
      await updateData(`games/${game.id}`, {
        ...game,
        listings: activeListingsForGame,
        minPrice: minPrice !== Infinity ? Math.floor(minPrice) : 0
      });
    }
  };

  // ===== ЧАТЫ =====
  const sendMessage = async (messageData) => {
    try {
      const chatId = messageData.chatId;
      
      const existingChat = chats.find(c => c.id === chatId);
      
      if (!existingChat) {
        const newChat = {
          id: chatId,
          listingId: messageData.listingId,
          participants: [messageData.fromUserId, messageData.toUserId],
          createdAt: new Date().toISOString(),
          messages: [messageData],
          updatedAt: new Date().toISOString()
        };
        await pushData('chats', newChat);
      } else {
        const updatedMessages = [...(existingChat.messages || []), {
          ...messageData,
          id: Date.now()
        }];
        await updateData(`chats/${chatId}`, {
          ...existingChat,
          messages: updatedMessages,
          updatedAt: new Date().toISOString()
        });
      }

      return { success: true };
    } catch (error) {
      console.error('Ошибка отправки сообщения:', error);
      return { success: false, error: error.message };
    }
  };

  const getMessages = (chatId) => {
    const chat = chats.find(c => c.id === chatId);
    return chat?.messages || [];
  };

  const getOrCreateChat = async (listingId, fromUserId, toUserId) => {
    const chatId = `${listingId}_${Math.min(fromUserId, toUserId)}_${Math.max(fromUserId, toUserId)}`;
    return chatId;
  };

  const markAsRead = async (chatId) => {
    try {
      const chat = chats.find(c => c.id === chatId);
      if (chat) {
        const updatedMessages = chat.messages?.map(m => ({
          ...m,
          read: true
        }));
        await updateData(`chats/${chatId}`, { ...chat, messages: updatedMessages });
      }
    } catch (error) {
      console.error('Ошибка отметки прочитанных:', error);
    }
  };

  const getUserChats = (userId) => {
    return chats.filter(chat => 
      chat.participants?.includes(userId)
    ).sort((a, b) => {
      const aTime = a.updatedAt || a.createdAt;
      const bTime = b.updatedAt || b.createdAt;
      return new Date(bTime) - new Date(aTime);
    });
  };

  const value = {
    currentUser,
    users,
    reviews,
    games,
    categories,
    allListings,
    chats,
    supportTickets,
    blockedUsers,
    transactions,
    unreadCount,
    unreadSupportCount,
    loading,
    loginWithTelegram,
    logout,
    addReview,
    getUserReviews,
    deleteReview,
    getAllUsers,
    changeUserRole,
    getGames,
    addGame,
    updateGame,
    deleteGame,
    getCategories,
    addCategory,
    updateCategory,
    deleteCategory,
    getCategoriesByGame,
    getAllListings,
    createListing,
    deleteListing,
    completeListing,
    sendMessage,
    getMessages,
    getOrCreateChat,
    markAsRead,
    getUserChats,
    isAdmin,
    isSupport,
    isBlocked,
    blockUser,
    unblockUser,
    createSupportTicket,
    addTicketMessage,
    closeSupportTicket,
    getUserTickets,
    getAllSupportTickets,
    refundTransaction
  };

  return (
    <UserContext.Provider value={value}>
      {children}
    </UserContext.Provider>
  );
}