import React, { useState, useEffect } from 'react';
import { useUser } from '../context/UserContext';
import { useBalance } from '../context/BalanceContext';
import { useNotification } from '../components/Notification';

function Admin() {
  const { 
    currentUser, 
    isAdmin,
    getAllUsers, 
    changeUserRole, 
    reviews, 
    deleteReview,
    users,
    games,
    getGames,
    addGame,
    updateGame,
    deleteGame,
    getCategories,
    addCategory,
    updateCategory,
    deleteCategory,
    getAllListings,
    deleteListing
  } = useUser();
  
  const { 
    platformBalance, 
    transactions, 
    sbpPayments, 
    withdrawRequests,
    approveSbpPayment, 
    rejectSbpPayment, 
    getAllSbpPayments,
    approveWithdraw,
    rejectWithdraw
  } = useBalance();
  
  const { showNotification } = useNotification();
  
  const [activeTab, setActiveTab] = useState('dashboard');
  const [gamesList, setGamesList] = useState([]);
  const [categoriesList, setCategoriesList] = useState([]);
  const [listingsList, setListingsList] = useState([]);
  const [paymentsList, setPaymentsList] = useState([]);
  const [employeesList, setEmployeesList] = useState([]);
  const [withdrawalsList, setWithdrawalsList] = useState([]);
  
  // Для игр
  const [editingGame, setEditingGame] = useState(null);
  const [showGameModal, setShowGameModal] = useState(false);
  const [gameForm, setGameForm] = useState({
    name: '',
    icon: '🎮'
  });
  const [gameImage, setGameImage] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);

  // Для подкатегорий
  const [editingCategory, setEditingCategory] = useState(null);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [categoryForm, setCategoryForm] = useState({
    name: '',
    gameId: '',
    description: ''
  });

  // Для платежей
  const [rejectReason, setRejectReason] = useState('');
  const [showRejectModal, setShowRejectModal] = useState(false);
  const [selectedPayment, setSelectedPayment] = useState(null);

  // Для выводов
  const [showWithdrawRejectModal, setShowWithdrawRejectModal] = useState(false);
  const [selectedWithdraw, setSelectedWithdraw] = useState(null);
  const [withdrawRejectReason, setWithdrawRejectReason] = useState('');

  // Загрузка данных
  useEffect(() => {
    setGamesList(getGames());
    setCategoriesList(getCategories());
    setListingsList(getAllListings());
    setPaymentsList(getAllSbpPayments());
    setWithdrawalsList(withdrawRequests || []);
    setEmployeesList(users.filter(u => u.role === 'support' || u.role === 'admin'));
  }, [getGames, getCategories, getAllListings, getAllSbpPayments, users, withdrawRequests]);

  // Проверка прав администратора
  if (!currentUser || !isAdmin()) {
    return (
      <div style={{ textAlign: 'center', padding: '3rem' }}>
        <h2>⛔ Доступ запрещен</h2>
        <p>Эта страница только для администраторов</p>
        <p>Ваш Telegram ID: {currentUser?.telegramId || 'не определен'}</p>
        <p>Нужный ID: 802498337</p>
        <button 
          className="btn btn-primary" 
          onClick={() => window.location.href = '#/'}
          style={{ marginTop: '2rem', width: 'auto' }}
        >
          На главную
        </button>
      </div>
    );
  }

  const allUsers = getAllUsers();
  const activeReviews = reviews.filter(r => !r.isDeleted);
  const pendingPayments = paymentsList.filter(p => p.status === 'pending');
  const pendingWithdrawals = withdrawalsList.filter(w => w.status === 'pending');

  // Статистика
  const totalCommission = transactions
    ? transactions.filter(t => t.commission).reduce((sum, t) => sum + t.commission, 0)
    : 0;

  const totalTrades = transactions ? transactions.filter(t => t.type === 'purchase').length : 0;

  // ===== УПРАВЛЕНИЕ ИГРАМИ =====
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      setGameImage(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGameSubmit = async (e) => {
    e.preventDefault();
    
    if (!gameForm.name.trim()) {
      showNotification('Введите название игры', 'error');
      return;
    }

    if (editingGame) {
      await updateGame(editingGame.id, gameForm, gameImage);
      showNotification('Игра обновлена', 'success');
    } else {
      await addGame(gameForm, gameImage);
      showNotification('Игра добавлена', 'success');
    }

    setShowGameModal(false);
    setEditingGame(null);
    setGameForm({ name: '', icon: '🎮' });
    setGameImage(null);
    setImagePreview(null);
  };

  const handleEditGame = (game) => {
    setEditingGame(game);
    setGameForm({ name: game.name, icon: game.icon || '🎮' });
    if (game.imageUrl) {
      setImagePreview(game.imageUrl);
    }
    setShowGameModal(true);
  };

  const handleDeleteGame = (gameId) => {
    if (window.confirm('Удалить эту игру?')) {
      deleteGame(gameId);
      showNotification('Игра удалена', 'success');
    }
  };

  // ===== УПРАВЛЕНИЕ ПОДКАТЕГОРИЯМИ =====
  const handleCategorySubmit = (e) => {
    e.preventDefault();
    
    if (!categoryForm.name.trim() || !categoryForm.gameId) {
      showNotification('Заполните все поля', 'error');
      return;
    }

    if (editingCategory) {
      updateCategory(editingCategory.id, categoryForm);
      showNotification('Подкатегория обновлена', 'success');
    } else {
      addCategory(categoryForm);
      showNotification('Подкатегория добавлена', 'success');
    }

    setShowCategoryModal(false);
    setEditingCategory(null);
    setCategoryForm({ name: '', gameId: '', description: '' });
  };

  const handleEditCategory = (category) => {
    setEditingCategory(category);
    setCategoryForm({
      name: category.name,
      gameId: category.gameId,
      description: category.description || ''
    });
    setShowCategoryModal(true);
  };

  const handleDeleteCategory = (categoryId) => {
    if (window.confirm('Удалить эту подкатегорию?')) {
      deleteCategory(categoryId);
      showNotification('Подкатегория удалена', 'success');
    }
  };

  // ===== УПРАВЛЕНИЕ ОБЪЯВЛЕНИЯМИ =====
  const handleDeleteListing = (listingId) => {
    if (window.confirm('Удалить это объявление?')) {
      deleteListing(listingId);
      showNotification('Объявление удалено', 'success');
    }
  };

  // ===== УПРАВЛЕНИЕ ПЛАТЕЖАМИ СБП =====
  const handleApprovePayment = async (payment) => {
    if (window.confirm(`Подтвердить пополнение на ${payment.amount} ₽ для пользователя ${payment.username}?`)) {
      const result = await approveSbpPayment(payment.id, currentUser.id);
      if (result.success) {
        showNotification(`Платеж подтвержден, баланс пользователя ${payment.username} пополнен`, 'success');
        setPaymentsList(getAllSbpPayments());
      } else {
        showNotification(result.error, 'error');
      }
    }
  };

  const handleRejectPayment = (payment) => {
    setSelectedPayment(payment);
    setShowRejectModal(true);
  };

  const confirmReject = async () => {
    if (!rejectReason.trim()) {
      showNotification('Укажите причину отказа', 'error');
      return;
    }

    const result = await rejectSbpPayment(selectedPayment.id, rejectReason);
    if (result.success) {
      showNotification('Платеж отклонен', 'success');
    } else {
      showNotification(result.error, 'error');
    }
    
    setShowRejectModal(false);
    setSelectedPayment(null);
    setRejectReason('');
    setPaymentsList(getAllSbpPayments());
  };

  // ===== УПРАВЛЕНИЕ ВЫВОДАМИ =====
  const handleApproveWithdraw = async (withdraw) => {
    if (window.confirm(`Подтвердить вывод ${withdraw.amount} ₽ для пользователя ${withdraw.username}?`)) {
      const result = await approveWithdraw(withdraw.id, currentUser.id);
      if (result.success) {
        showNotification(`Вывод подтвержден`, 'success');
        setWithdrawalsList(withdrawRequests);
      } else {
        showNotification(result.error, 'error');
      }
    }
  };

  const handleRejectWithdraw = (withdraw) => {
    setSelectedWithdraw(withdraw);
    setShowWithdrawRejectModal(true);
  };

  const confirmWithdrawReject = async () => {
    if (!withdrawRejectReason.trim()) {
      showNotification('Укажите причину отказа', 'error');
      return;
    }

    const result = await rejectWithdraw(selectedWithdraw.id, withdrawRejectReason);
    if (result.success) {
      showNotification('Вывод отклонен, средства возвращены на баланс', 'success');
    } else {
      showNotification(result.error, 'error');
    }
    
    setShowWithdrawRejectModal(false);
    setSelectedWithdraw(null);
    setWithdrawRejectReason('');
    setWithdrawalsList(withdrawRequests);
  };

  return (
    <div>
      <h1 className="section-title">Панель администратора</h1>
      
      <div style={{ 
        background: 'var(--gradient)', 
        color: 'white', 
        padding: '1rem', 
        borderRadius: '8px', 
        marginBottom: '2rem',
        textAlign: 'center'
      }}>
        👑 Добро пожаловать, {currentUser.firstName}! (ID: {currentUser.telegramId})
        <div style={{ marginTop: '0.5rem', display: 'flex', gap: '1rem', justifyContent: 'center' }}>
          {pendingPayments.length > 0 && (
            <span style={{ background: 'rgba(255,255,255,0.2)', padding: '0.3rem 0.8rem', borderRadius: '4px' }}>
              💳 Платежи: {pendingPayments.length}
            </span>
          )}
          {pendingWithdrawals.length > 0 && (
            <span style={{ background: 'rgba(255,255,255,0.2)', padding: '0.3rem 0.8rem', borderRadius: '4px' }}>
              💸 Выводы: {pendingWithdrawals.length}
            </span>
          )}
        </div>
      </div>

      {/* Статистика */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
        gap: '1rem',
        marginBottom: '2rem'
      }}>
        <div className="listing-card">
          <h3>👥 Пользователи</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold' }}>{allUsers.length}</div>
        </div>
        <div className="listing-card">
          <h3>💰 Баланс платформы</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--primary)' }}>
            {platformBalance.toLocaleString()} ₽
          </div>
        </div>
        <div className="listing-card">
          <h3>📊 Всего комиссии</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--success)' }}>
            {totalCommission.toLocaleString()} ₽
          </div>
        </div>
        <div className="listing-card">
          <h3>🔄 Сделок</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold' }}>{totalTrades}</div>
        </div>
        <div className="listing-card">
          <h3>🎮 Игр</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold' }}>{gamesList.length}</div>
        </div>
        <div className="listing-card">
          <h3>🏷️ Подкатегорий</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold' }}>{categoriesList.length}</div>
        </div>
        <div className="listing-card">
          <h3>📢 Объявлений</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold' }}>{listingsList.length}</div>
        </div>
      </div>

      {/* Вкладки */}
      <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem', flexWrap: 'wrap' }}>
        <button
          className={`btn ${activeTab === 'dashboard' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('dashboard')}
          style={{ width: 'auto' }}
        >
          📊 Дашборд
        </button>
        <button
          className={`btn ${activeTab === 'payments' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('payments')}
          style={{ width: 'auto', position: 'relative' }}
        >
          💳 Платежи СБП
          {pendingPayments.length > 0 && (
            <span style={{
              position: 'absolute',
              top: '-5px',
              right: '-5px',
              background: 'var(--danger)',
              color: 'white',
              borderRadius: '50%',
              width: '20px',
              height: '20px',
              fontSize: '12px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>
              {pendingPayments.length}
            </span>
          )}
        </button>
        <button
          className={`btn ${activeTab === 'withdrawals' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('withdrawals')}
          style={{ width: 'auto', position: 'relative' }}
        >
          💸 Выводы
          {pendingWithdrawals.length > 0 && (
            <span style={{
              position: 'absolute',
              top: '-5px',
              right: '-5px',
              background: 'var(--danger)',
              color: 'white',
              borderRadius: '50%',
              width: '20px',
              height: '20px',
              fontSize: '12px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}>
              {pendingWithdrawals.length}
            </span>
          )}
        </button>
        <button
          className={`btn ${activeTab === 'users' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('users')}
          style={{ width: 'auto' }}
        >
          👥 Пользователи
        </button>
        <button
          className={`btn ${activeTab === 'employees' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('employees')}
          style={{ width: 'auto' }}
        >
          👥 Сотрудники ({employeesList.length})
        </button>
        <button
          className={`btn ${activeTab === 'games' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('games')}
          style={{ width: 'auto' }}
        >
          🎮 Игры
        </button>
        <button
          className={`btn ${activeTab === 'categories' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('categories')}
          style={{ width: 'auto' }}
        >
          🏷️ Подкатегории ({categoriesList.length})
        </button>
        <button
          className={`btn ${activeTab === 'listings' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('listings')}
          style={{ width: 'auto' }}
        >
          📢 Объявления
        </button>
        <button
          className={`btn ${activeTab === 'reviews' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('reviews')}
          style={{ width: 'auto' }}
        >
          ⭐ Отзывы ({activeReviews.length})
        </button>
        <button
          className={`btn ${activeTab === 'transactions' ? 'btn-primary' : 'btn-outline'}`}
          onClick={() => setActiveTab('transactions')}
          style={{ width: 'auto' }}
        >
          💳 Транзакции
        </button>
      </div>

      {/* ===== ВКЛАДКА: ВЫВОДЫ ===== */}
      {activeTab === 'withdrawals' && (
        <div>
          <h2>Управление выводами средств</h2>
          
          {/* Ожидающие выводы */}
          <div style={{ marginTop: '2rem' }}>
            <h3>⏳ Ожидают обработки ({pendingWithdrawals.length})</h3>
            {pendingWithdrawals.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет заявок на вывод</p>
              </div>
            ) : (
              pendingWithdrawals.map(request => (
                <div key={request.id} className="listing-card" style={{ marginBottom: '1rem', borderLeft: '4px solid var(--warning)' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: '1rem' }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.5rem' }}>
                        <div className="avatar">💸</div>
                        <div>
                          <div><strong>Пользователь:</strong> {request.username} (ID: {request.userId})</div>
                          <div><strong>Сумма:</strong> {request.amount} ₽</div>
                          <div><strong>Способ:</strong> {request.method === 'card' ? '💳 Карта' : '🏦 СБП'}</div>
                          {request.method === 'card' && (
                            <div><strong>Карта:</strong> {request.cardNumber}</div>
                          )}
                          {request.method === 'sbp' && (
                            <>
                              <div><strong>Телефон:</strong> {request.phoneNumber}</div>
                              <div><strong>Банк:</strong> {request.bank}</div>
                            </>
                          )}
                          <div><strong>Дата:</strong> {new Date(request.createdAt).toLocaleString()}</div>
                          <div><small>Обработка до {request.estimatedProcessingDays} дней</small></div>
                        </div>
                      </div>
                    </div>
                    
                    <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                      <button
                        className="btn btn-success"
                        onClick={() => handleApproveWithdraw(request)}
                        style={{ width: 'auto', background: 'var(--success)' }}
                      >
                        ✓ Подтвердить
                      </button>
                      <button
                        className="btn btn-danger"
                        onClick={() => handleRejectWithdraw(request)}
                        style={{ width: 'auto' }}
                      >
                        ✗ Отклонить
                      </button>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>

          {/* История выводов */}
          <div style={{ marginTop: '2rem' }}>
            <h3>📋 История выводов</h3>
            {withdrawalsList.filter(w => w.status !== 'pending').length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет обработанных заявок</p>
              </div>
            ) : (
              withdrawalsList.filter(w => w.status !== 'pending').map(request => (
                <div key={request.id} className="listing-card" style={{ marginBottom: '1rem', opacity: 0.8 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap' }}>
                    <div>
                      <div><strong>{request.username}</strong> - {request.amount} ₽</div>
                      <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                        {request.method === 'card' ? request.cardNumber : `${request.bank} (${request.phoneNumber})`}
                      </div>
                      <div style={{ fontSize: '0.8rem', marginTop: '0.25rem' }}>
                        {new Date(request.createdAt).toLocaleString()}
                      </div>
                    </div>
                    <div style={{
                      padding: '0.25rem 0.75rem',
                      borderRadius: '20px',
                      fontSize: '0.8rem',
                      background: request.status === 'completed' ? '#e8f5e9' : '#fee2e2',
                      color: request.status === 'completed' ? 'var(--success)' : 'var(--danger)'
                    }}>
                      {request.status === 'completed' ? '✅ Подтвержден' : '❌ Отклонен'}
                      {request.rejectReason && <div>Причина: {request.rejectReason}</div>}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: ПЛАТЕЖИ СБП ===== */}
      {activeTab === 'payments' && (
        <div>
          <h2>Подтверждение СБП платежей</h2>
          
          <div style={{ marginTop: '1rem' }}>
            <h3>Ожидают подтверждения ({pendingPayments.length})</h3>
            {pendingPayments.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет платежей на подтверждении</p>
              </div>
            ) : (
              pendingPayments.map(payment => (
                <div key={payment.id} className="listing-card" style={{ marginBottom: '1rem', borderLeft: '4px solid var(--warning)' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', flexWrap: 'wrap', gap: '1rem' }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '0.5rem' }}>
                        <div className="avatar">💳</div>
                        <div>
                          <div><strong>Пользователь:</strong> {payment.username} (ID: {payment.userId})</div>
                          <div><strong>Сумма:</strong> {payment.amount} ₽</div>
                          <div><strong>Карта:</strong> {payment.cardNumber}</div>
                          <div><strong>Дата:</strong> {new Date(payment.date).toLocaleString()}</div>
                        </div>
                      </div>
                    </div>
                    
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <button
                        className="btn btn-success"
                        onClick={() => handleApprovePayment(payment)}
                        style={{ width: 'auto', background: 'var(--success)' }}
                      >
                        ✓ Подтвердить
                      </button>
                      <button
                        className="btn btn-danger"
                        onClick={() => handleRejectPayment(payment)}
                        style={{ width: 'auto' }}
                      >
                        ✗ Отклонить
                      </button>
                    </div>
                  </div>
                </div>
              ))
            )}

            <h3 style={{ marginTop: '2rem' }}>История платежей</h3>
            {paymentsList.filter(p => p.status !== 'pending').map(payment => (
              <div key={payment.id} className="listing-card" style={{ marginBottom: '1rem', opacity: 0.8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <div><strong>{payment.username}</strong> - {payment.amount} ₽</div>
                    <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                      Карта: {payment.cardNumber} • {new Date(payment.date).toLocaleString()}
                    </div>
                    {payment.status === 'approved' && (
                      <div style={{ color: 'var(--success)' }}>
                        ✓ Подтвержден {payment.confirmedBy && `админом ${payment.confirmedBy}`} {payment.confirmedAt && new Date(payment.confirmedAt).toLocaleString()}
                      </div>
                    )}
                    {payment.status === 'rejected' && (
                      <div style={{ color: 'var(--danger)' }}>
                        ✗ Отклонен: {payment.rejectReason}
                      </div>
                    )}
                  </div>
                  <div style={{
                    padding: '0.25rem 0.75rem',
                    borderRadius: '20px',
                    fontSize: '0.8rem',
                    background: payment.status === 'approved' ? '#e8f5e9' : '#fee2e2',
                    color: payment.status === 'approved' ? 'var(--success)' : 'var(--danger)'
                  }}>
                    {payment.status === 'approved' ? 'Подтвержден' : 'Отклонен'}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: ДАШБОРД ===== */}
      {activeTab === 'dashboard' && (
        <div>
          <h2>Быстрые действия</h2>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '1rem', marginTop: '1rem' }}>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('payments')}>
              <h3>💳 Подтвердить платежи {pendingPayments.length > 0 && `(${pendingPayments.length})`}</h3>
              <p>Проверить СБП переводы и начислить баланс</p>
            </div>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('withdrawals')}>
              <h3>💸 Обработать выводы {pendingWithdrawals.length > 0 && `(${pendingWithdrawals.length})`}</h3>
              <p>Подтвердить или отклонить заявки на вывод</p>
            </div>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('games')}>
              <h3>➕ Добавить игру</h3>
              <p>Создать новую категорию игры</p>
            </div>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('categories')}>
              <h3>🏷️ Добавить подкатегорию</h3>
              <p>Создать подкатегорию для игры</p>
            </div>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('employees')}>
              <h3>👥 Управление сотрудниками</h3>
              <p>Назначить роли поддержки</p>
            </div>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('listings')}>
              <h3>🗑️ Модерация объявлений</h3>
              <p>Проверить и удалить нарушения</p>
            </div>
            <div className="listing-card" style={{ cursor: 'pointer' }} onClick={() => setActiveTab('reviews')}>
              <h3>⭐ Модерация отзывов</h3>
              <p>Проверить жалобы на отзывы</p>
            </div>
          </div>

          {/* Последние действия */}
          <h2 style={{ marginTop: '2rem' }}>Последние транзакции</h2>
          <div style={{ marginTop: '1rem' }}>
            {transactions && transactions.slice(0, 5).map(t => (
              <div key={t.id} className="listing-card" style={{ marginBottom: '0.5rem', padding: '0.75rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                  <span>
                    {t.type === 'deposit' && '💰 Пополнение'}
                    {t.type === 'withdraw_request' && '💸 Заявка на вывод'}
                    {t.type === 'withdraw' && '💸 Вывод'}
                    {t.type === 'purchase' && '🛒 Покупка'}
                    {t.type === 'sbp_request' && '💳 Заявка СБП'} - {t.username}
                  </span>
                  <span style={{ fontWeight: 'bold' }}>{t.amount || t.price} ₽</span>
                </div>
                <div style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>
                  {new Date(t.date).toLocaleString()}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: ПОЛЬЗОВАТЕЛИ ===== */}
      {activeTab === 'users' && (
        <div>
          <h2>Управление пользователями</h2>
          <div style={{ marginTop: '1rem' }}>
            {allUsers.map(user => (
              <div key={user.id} className="listing-card" style={{ marginBottom: '1rem' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <div 
                      className="avatar"
                      style={{
                        border: user.role === 'support' ? '2px solid var(--success)' : 
                                user.role === 'admin' ? '2px solid var(--primary)' : 'none',
                        position: 'relative'
                      }}
                    >
                      {user.username?.[0]?.toUpperCase() || '?'}
                      {user.role === 'support' && (
                        <div style={{
                          position: 'absolute',
                          bottom: '-4px',
                          right: '-4px',
                          background: 'var(--success)',
                          color: 'white',
                          borderRadius: '50%',
                          width: '16px',
                          height: '16px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontSize: '10px',
                          border: '2px solid white'
                        }}>
                          🛟
                        </div>
                      )}
                    </div>
                    <div>
                      <div>
                        <strong>{user.firstName || ''} {user.lastName || ''}</strong>
                        {user.role === 'admin' && ' 👑'}
                        {user.role === 'support' && ' 🛟'}
                        {user.telegramId === 802498337 && ' 🔥 ВЛАДЕЛЕЦ'}
                      </div>
                      <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                        @{user.username || 'нет'} • ID: {user.id}
                      </div>
                      <div style={{ fontSize: '0.9rem' }}>
                        Рейтинг: {'★'.repeat(Math.round(user.stats?.avgRating || 0))}
                        {'☆'.repeat(5 - Math.round(user.stats?.avgRating || 0))}
                        ({user.stats?.totalTrades || 0} сделок)
                      </div>
                    </div>
                  </div>
                  
                  <div style={{ display: 'flex', gap: '0.5rem' }}>
                    <select
                      value={user.role || 'user'}
                      onChange={(e) => changeUserRole(user.id, e.target.value)}
                      className="search-select"
                      style={{ width: 'auto' }}
                      disabled={user.telegramId === 802498337}
                    >
                      <option value="user">Пользователь</option>
                      <option value="support">Техподдержка</option>
                      <option value="admin">Администратор</option>
                    </select>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: СОТРУДНИКИ ===== */}
      {activeTab === 'employees' && (
        <div>
          <h2>Управление сотрудниками</h2>
          <div style={{ marginTop: '1rem' }}>
            {employeesList.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет сотрудников</p>
              </div>
            ) : (
              employeesList.map(user => (
                <div key={user.id} className="listing-card" style={{ marginBottom: '1rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                      <div className="avatar" style={{
                        border: user.role === 'support' ? '2px solid var(--success)' : 
                                user.role === 'admin' ? '2px solid var(--primary)' : 'none'
                      }}>
                        {user.username?.[0]?.toUpperCase()}
                      </div>
                      <div>
                        <div>
                          <strong>{user.firstName} {user.lastName}</strong>
                          {user.role === 'admin' && ' 👑 Администратор'}
                          {user.role === 'support' && ' 🛟 Техподдержка'}
                        </div>
                        <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                          @{user.username} • {user.stats?.totalTrades || 0} сделок
                        </div>
                      </div>
                    </div>
                    
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <select
                        value={user.role}
                        onChange={(e) => changeUserRole(user.id, e.target.value)}
                        className="search-select"
                        style={{ width: 'auto' }}
                        disabled={user.telegramId === 802498337}
                      >
                        <option value="user">Пользователь</option>
                        <option value="support">Техподдержка</option>
                        <option value="admin">Администратор</option>
                      </select>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: ИГРЫ ===== */}
      {activeTab === 'games' && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h2>Управление играми</h2>
            <button 
              className="btn btn-primary"
              onClick={() => {
                setEditingGame(null);
                setGameForm({ name: '', icon: '🎮' });
                setImagePreview(null);
                setGameImage(null);
                setShowGameModal(true);
              }}
              style={{ width: 'auto' }}
            >
              ➕ Добавить игру
            </button>
          </div>

          <div className="games-grid">
            {gamesList.map(game => (
              <div key={game.id} className="game-card">
                <div 
                  className="game-image" 
                  style={{
                    background: game.imageUrl ? `url(${game.imageUrl})` : 'var(--gradient)',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    fontSize: game.imageUrl ? '0' : '3rem'
                  }}
                >
                  {!game.imageUrl && (game.icon || '🎮')}
                </div>
                <div className="game-info">
                  <div className="game-name">{game.name}</div>
                  <div className="game-stats">
                    <span>📊 {game.listings || 0} объявлений</span>
                    <span>💰 от {game.minPrice || 0} ₽</span>
                  </div>
                  <div style={{ display: 'flex', gap: '0.5rem', marginTop: '1rem' }}>
                    <button 
                      className="btn btn-outline"
                      onClick={() => handleEditGame(game)}
                      style={{ flex: 1 }}
                    >
                      ✏️
                    </button>
                    <button 
                      className="btn btn-outline"
                      onClick={() => handleDeleteGame(game.id)}
                      style={{ flex: 1, color: 'var(--danger)' }}
                    >
                      🗑️
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Модалка добавления/редактирования игры */}
          {showGameModal && (
            <div className="modal-overlay" onClick={() => setShowGameModal(false)}>
              <div className="modal" onClick={e => e.stopPropagation()}>
                <span className="modal-close" onClick={() => setShowGameModal(false)}>&times;</span>
                <h2>{editingGame ? 'Редактировать игру' : 'Добавить игру'}</h2>
                
                <form onSubmit={handleGameSubmit}>
                  <div className="form-group">
                    <label>Название игры *</label>
                    <input
                      type="text"
                      value={gameForm.name}
                      onChange={(e) => setGameForm({ ...gameForm, name: e.target.value })}
                      placeholder="Например: World of Warcraft"
                      required
                    />
                  </div>
                  
                  <div className="form-group">
                    <label>Иконка (эмодзи) - необязательно, если есть картинка</label>
                    <input
                      type="text"
                      value={gameForm.icon}
                      onChange={(e) => setGameForm({ ...gameForm, icon: e.target.value })}
                      placeholder="Например: ⚔️"
                    />
                  </div>

                  <div className="form-group">
                    <label>Изображение игры</label>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleImageChange}
                      style={{ padding: '0.5rem' }}
                    />
                    {imagePreview && (
                      <div style={{ marginTop: '1rem', textAlign: 'center' }}>
                        <img 
                          src={imagePreview} 
                          alt="Превью" 
                          style={{ 
                            maxWidth: '200px', 
                            maxHeight: '200px',
                            borderRadius: '8px',
                            border: '1px solid var(--border)'
                          }} 
                        />
                      </div>
                    )}
                  </div>

                  <button type="submit" className="btn btn-primary">
                    {editingGame ? 'Сохранить' : 'Добавить'}
                  </button>
                </form>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ===== ВКЛАДКА: ПОДКАТЕГОРИИ ===== */}
      {activeTab === 'categories' && (
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
            <h2>Управление подкатегориями</h2>
            <button 
              className="btn btn-primary"
              onClick={() => {
                setEditingCategory(null);
                setCategoryForm({ name: '', gameId: '', description: '' });
                setShowCategoryModal(true);
              }}
              style={{ width: 'auto' }}
            >
              ➕ Добавить подкатегорию
            </button>
          </div>

          <div style={{ marginTop: '1rem' }}>
            {categoriesList.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет подкатегорий</p>
              </div>
            ) : (
              categoriesList.map(category => {
                const game = games.find(g => g.id === category.gameId);
                return (
                  <div key={category.id} className="listing-card" style={{ marginBottom: '1rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
                      <div>
                        <h3 style={{ marginBottom: '0.25rem' }}>{category.name}</h3>
                        <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                          Игра: {game?.name || 'Неизвестно'}
                        </div>
                        {category.description && (
                          <div style={{ fontSize: '0.9rem', marginTop: '0.25rem' }}>
                            {category.description}
                          </div>
                        )}
                      </div>
                      
                      <div style={{ display: 'flex', gap: '0.5rem' }}>
                        <button 
                          className="btn btn-outline"
                          onClick={() => handleEditCategory(category)}
                          style={{ width: 'auto' }}
                        >
                          ✏️
                        </button>
                        <button 
                          className="btn btn-outline"
                          onClick={() => handleDeleteCategory(category.id)}
                          style={{ width: 'auto', color: 'var(--danger)' }}
                        >
                          🗑️
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })
            )}
          </div>

          {/* Модалка для категорий */}
          {showCategoryModal && (
            <div className="modal-overlay" onClick={() => setShowCategoryModal(false)}>
              <div className="modal" onClick={e => e.stopPropagation()}>
                <span className="modal-close" onClick={() => setShowCategoryModal(false)}>&times;</span>
                <h2>{editingCategory ? 'Редактировать подкатегорию' : 'Добавить подкатегорию'}</h2>
                
                <form onSubmit={handleCategorySubmit}>
                  <div className="form-group">
                    <label>Игра *</label>
                    <select
                      value={categoryForm.gameId}
                      onChange={(e) => setCategoryForm({ ...categoryForm, gameId: e.target.value })}
                      required
                    >
                      <option value="">Выберите игру</option>
                      {games.map(game => (
                        <option key={game.id} value={game.id}>{game.name}</option>
                      ))}
                    </select>
                  </div>

                  <div className="form-group">
                    <label>Название подкатегории *</label>
                    <input
                      type="text"
                      value={categoryForm.name}
                      onChange={(e) => setCategoryForm({ ...categoryForm, name: e.target.value })}
                      placeholder="Например: Gold, MMR, Скины"
                      required
                    />
                  </div>
                  
                  <div className="form-group">
                    <label>Описание (необязательно)</label>
                    <textarea
                      value={categoryForm.description}
                      onChange={(e) => setCategoryForm({ ...categoryForm, description: e.target.value })}
                      placeholder="Краткое описание категории"
                      rows="3"
                    />
                  </div>

                  <button type="submit" className="btn btn-primary">
                    {editingCategory ? 'Сохранить' : 'Добавить'}
                  </button>
                </form>
              </div>
            </div>
          )}
        </div>
      )}

      {/* ===== ВКЛАДКА: ОБЪЯВЛЕНИЯ ===== */}
      {activeTab === 'listings' && (
        <div>
          <h2>Управление объявлениями</h2>
          <div style={{ marginTop: '1rem' }}>
            {listingsList.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет активных объявлений</p>
              </div>
            ) : (
              listingsList.map(listing => (
                <div key={listing.id} className="listing-card" style={{ marginBottom: '1rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', flexWrap: 'wrap', gap: '1rem' }}>
                    <div style={{ flex: 1 }}>
                      <div className="listing-header">
                        <span className="listing-game">{listing.game}</span>
                        <span className={`listing-type ${listing.type === 'buy' ? 'type-buy' : 'type-sell'}`}>
                          {listing.type === 'buy' ? 'Покупка' : 'Продажа'}
                        </span>
                      </div>
                      {listing.category && (
                        <div style={{ 
                          fontSize: '0.8rem', 
                          color: 'var(--primary)', 
                          marginBottom: '0.5rem',
                          padding: '0.2rem 0.5rem',
                          background: 'rgba(108, 92, 231, 0.1)',
                          borderRadius: '4px',
                          display: 'inline-block'
                        }}>
                          {listing.category}
                        </div>
                      )}
                      <div className="listing-amount">
                        {listing.amount} {listing.currency}
                      </div>
                      <div className="listing-price">
                        <span>{listing.price} ₽</span>
                      </div>
                      <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                        Продавец: {listing.seller} • Дата: {new Date(listing.date).toLocaleDateString()}
                      </div>
                    </div>
                    
                    <button
                      className="btn btn-danger"
                      onClick={() => handleDeleteListing(listing.id)}
                      style={{ width: 'auto' }}
                    >
                      🗑️ Удалить
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: ОТЗЫВЫ ===== */}
      {activeTab === 'reviews' && (
        <div>
          <h2>Модерация отзывов</h2>
          <div style={{ marginTop: '1rem' }}>
            {activeReviews.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет отзывов на модерации</p>
              </div>
            ) : (
              activeReviews.map(review => {
                const fromUser = users.find(u => u.id === review.fromUserId);
                const toUser = users.find(u => u.id === review.toUserId);
                
                return (
                  <div key={review.id} className="listing-card" style={{ marginBottom: '1rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', flexWrap: 'wrap', gap: '1rem' }}>
                      <div style={{ flex: 1 }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: '1rem' }}>
                          <div className="avatar" style={{ width: '30px', height: '30px' }}>
                            {fromUser?.username?.[0] || '?'}
                          </div>
                          <div>
                            <strong>{fromUser?.username || 'Пользователь'}</strong>
                            <span style={{ color: 'var(--gray)', marginLeft: '0.5rem' }}>
                              → {toUser?.username || 'Пользователь'}
                            </span>
                          </div>
                          <div style={{ fontSize: '1.2rem', color: '#ffc107', marginLeft: '1rem' }}>
                            {'★'.repeat(review.rating)}
                            {'☆'.repeat(5 - review.rating)}
                          </div>
                        </div>
                        
                        <p style={{ marginBottom: '0.5rem' }}>{review.comment}</p>
                        
                        <div style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                          {new Date(review.date).toLocaleString()}
                        </div>
                      </div>
                      
                      <button
                        className="btn btn-danger"
                        onClick={() => deleteReview(review.id)}
                        style={{ width: 'auto' }}
                      >
                        🗑️ Удалить
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      )}

      {/* ===== ВКЛАДКА: ТРАНЗАКЦИИ ===== */}
      {activeTab === 'transactions' && (
        <div>
          <h2>Все транзакции</h2>
          <div style={{ marginTop: '1rem' }}>
            {transactions.length === 0 ? (
              <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
                <p>Нет транзакций</p>
              </div>
            ) : (
              transactions.map(t => (
                <div key={t.id} className="listing-card" style={{ marginBottom: '0.5rem', padding: '0.75rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                      <strong>
                        {t.type === 'deposit' && '💰 Пополнение'}
                        {t.type === 'withdraw_request' && '💸 Заявка на вывод'}
                        {t.type === 'withdraw' && '💸 Вывод'}
                        {t.type === 'purchase' && '🛒 Покупка'}
                        {t.type === 'sbp_request' && '💳 Заявка СБП'}
                        {t.type === 'listing_created' && '📢 Создание объявления'}
                      </strong>
                      {t.commission && <span style={{ color: 'var(--primary)' }}> (комиссия: {t.commission} ₽)</span>}
                      <div style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>
                        {new Date(t.date).toLocaleString()} • {t.username}
                      </div>
                    </div>
                    <div style={{ 
                      fontSize: '1.1rem',
                      fontWeight: 'bold',
                      color: t.type === 'deposit' || t.type === 'listing_created' ? 'var(--success)' : 'var(--danger)'
                    }}>
                      {t.type === 'deposit' || t.type === 'listing_created' ? '+' : '-'}
                      {t.amount || t.price} ₽
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}

      {/* Модалка отказа платежа */}
      {showRejectModal && (
        <div className="modal-overlay" onClick={() => setShowRejectModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <span className="modal-close" onClick={() => setShowRejectModal(false)}>&times;</span>
            <h2>Отклонить платеж</h2>
            
            <div className="form-group">
              <label>Причина отказа</label>
              <textarea
                rows="3"
                value={rejectReason}
                onChange={(e) => setRejectReason(e.target.value)}
                placeholder="Укажите причину отказа..."
                style={{ width: '100%', padding: '0.75rem' }}
              />
            </div>

            <div style={{ display: 'flex', gap: '1rem' }}>
              <button 
                className="btn btn-outline" 
                onClick={() => setShowRejectModal(false)}
                style={{ flex: 1 }}
              >
                Отмена
              </button>
              <button 
                className="btn btn-danger" 
                onClick={confirmReject}
                style={{ flex: 2 }}
              >
                Подтвердить отказ
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Модалка отказа вывода */}
      {showWithdrawRejectModal && (
        <div className="modal-overlay" onClick={() => setShowWithdrawRejectModal(false)}>
          <div className="modal" onClick={e => e.stopPropagation()}>
            <span className="modal-close" onClick={() => setShowWithdrawRejectModal(false)}>&times;</span>
            <h2>Отклонить вывод</h2>
            
            <div className="form-group">
              <label>Причина отказа</label>
              <textarea
                rows="3"
                value={withdrawRejectReason}
                onChange={(e) => setWithdrawRejectReason(e.target.value)}
                placeholder="Укажите причину отказа..."
                style={{ width: '100%', padding: '0.75rem' }}
              />
            </div>

            <div style={{ display: 'flex', gap: '1rem' }}>
              <button 
                className="btn btn-outline" 
                onClick={() => setShowWithdrawRejectModal(false)}
                style={{ flex: 1 }}
              >
                Отмена
              </button>
              <button 
                className="btn btn-danger" 
                onClick={confirmWithdrawReject}
                style={{ flex: 2 }}
              >
                Подтвердить отказ
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default Admin;