import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useBalance } from '../context/BalanceContext';
import { useUser } from '../context/UserContext';
import { useNotification } from './Notification';
import ReviewModal from './ReviewModal';

function TransactionModal({ isOpen, onClose, listing, type }) {
  const { buyItem, balance } = useBalance();
  const { currentUser } = useUser();
  const { showNotification } = useNotification();
  const navigate = useNavigate();
  
  const [step, setStep] = useState(1); // 1: подтверждение, 2: результат
  const [isReviewModalOpen, setIsReviewModalOpen] = useState(false);
  const [processing, setProcessing] = useState(false);

  const totalPrice = listing.price;
  const commission = Math.floor(totalPrice * 0.05);
  const sellerGets = totalPrice - commission;
  const hasEnoughMoney = balance >= totalPrice;

  const handleConfirm = async () => {
    if (type === 'buy') {
      setProcessing(true);
      
      // Небольшая задержка для имитации обработки
      setTimeout(async () => {
        const result = await buyItem(listing);
        
        if (result.success) {
          showNotification(
            `✅ Покупка успешно завершена! Товар: ${listing.amount} ${listing.currency} за ${listing.price} ₽`, 
            'success', 
            4000
          );
          setStep(2);
        } else {
          showNotification(result.error, 'error');
          onClose();
        }
        setProcessing(false);
      }, 500);
    }
  };

  const handleClose = () => {
    onClose();
    setStep(1);
  };

  const handleLeaveReview = () => {
    setIsReviewModalOpen(true);
  };

  const handleViewProfile = () => {
    const sellerId = listing.sellerId || 1;
    navigate(`/user/${sellerId}`);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <>
      <div className="modal-overlay" onClick={handleClose}>
        <div className="modal" onClick={e => e.stopPropagation()}>
          <span className="modal-close" onClick={handleClose}>&times;</span>
          
          {step === 1 && (
            <>
              <h2>Подтверждение покупки</h2>
              
              <div style={{ margin: '1.5rem 0' }}>
                <p><strong>Игра:</strong> {listing.game}</p>
                <p><strong>Количество:</strong> {listing.amount} {listing.currency}</p>
                <p><strong>Продавец:</strong> {listing.seller}</p>
                <p><strong>Цена:</strong> {listing.price} ₽</p>
                
                <div style={{ 
                  background: '#f5f5f5', 
                  padding: '1rem', 
                  borderRadius: '8px',
                  marginTop: '1rem'
                }}>
                  <p><strong>Комиссия платформы (5%):</strong> {commission} ₽</p>
                  <p><strong>Продавец получит:</strong> {sellerGets} ₽</p>
                  <p><strong>Спишется с баланса:</strong> {totalPrice} ₽</p>
                  <p><strong>Ваш баланс:</strong> {balance} ₽</p>
                  {!hasEnoughMoney && (
                    <p style={{ color: 'var(--danger)', marginTop: '0.5rem' }}>
                      ❌ Недостаточно средств. Пополните баланс.
                    </p>
                  )}
                </div>
              </div>

              <div style={{ display: 'flex', gap: '1rem' }}>
                <button 
                  className="btn btn-outline" 
                  onClick={handleClose}
                  disabled={processing}
                  style={{ flex: 1 }}
                >
                  Отмена
                </button>
                <button 
                  className="btn btn-primary" 
                  onClick={handleConfirm}
                  disabled={!hasEnoughMoney || processing}
                  style={{ 
                    flex: 2,
                    opacity: !hasEnoughMoney || processing ? 0.5 : 1,
                    cursor: !hasEnoughMoney || processing ? 'not-allowed' : 'pointer'
                  }}
                >
                  {processing ? 'Обработка...' : 'Подтвердить покупку'}
                </button>
              </div>
            </>
          )}

          {step === 2 && (
            <>
              <h2 style={{ color: 'var(--success)' }}>✓ Покупка успешна!</h2>
              
              <div style={{ textAlign: 'center', margin: '2rem 0' }}>
                <p>Сделка успешно завершена!</p>
                <p>С вашего баланса списано: {totalPrice} ₽</p>
                <p>Комиссия платформы: {commission} ₽</p>
                <p>Свяжитесь с продавцом <strong>{listing.seller}</strong> для получения товара.</p>
              </div>

              <div style={{ display: 'flex', gap: '1rem', flexDirection: 'column' }}>
                <button 
                  className="btn btn-primary" 
                  onClick={handleLeaveReview}
                >
                  ⭐ Оставить отзыв о продавце
                </button>
                
                <button 
                  className="btn btn-outline" 
                  onClick={handleViewProfile}
                >
                  👤 Посмотреть профиль продавца
                </button>
                
                <button 
                  className="btn btn-outline" 
                  onClick={handleClose}
                >
                  Закрыть
                </button>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Модалка отзыва */}
      {listing && (
        <ReviewModal
          isOpen={isReviewModalOpen}
          onClose={() => {
            setIsReviewModalOpen(false);
            onClose();
          }}
          sellerId={listing.sellerId || 1}
          sellerName={listing.seller}
          transactionId={listing.id}
        />
      )}
    </>
  );
}

export default TransactionModal;