import React, { useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import { useNotification } from '../components/Notification';

function Login() {
  const { loginWithTelegram, currentUser } = useUser();
  const { showNotification } = useNotification();
  const navigate = useNavigate();

  useEffect(() => {
    // Если уже авторизован, перенаправляем на главную
    if (currentUser) {
      navigate('/');
    }
  }, [currentUser, navigate]);

  useEffect(() => {
    // Функция обработки данных от Telegram
    window.handleTelegramAuth = (user) => {
      console.log('Telegram auth data:', user);
      
      if (!user || !user.id) {
        showNotification('Ошибка авторизации', 'error');
        return;
      }

      const loggedInUser = loginWithTelegram(user);
      
      if (loggedInUser) {
        showNotification(`Добро пожаловать, ${loggedInUser.firstName}!`, 'success');
        navigate('/');
      }
    };

    // Загружаем скрипт Telegram Widget
    const script = document.createElement('script');
    script.src = 'https://telegram.org/js/telegram-widget.js?22';
    script.setAttribute('data-telegram-login', 'VisorMarketbot'); // ← ЗАМЕНИ НА ИМЯ ТВОЕГО БОТА
    script.setAttribute('data-size', 'large');
    script.setAttribute('data-radius', '8');
    script.setAttribute('data-request-access', 'write');
    script.setAttribute('data-userpic', 'true');
    script.setAttribute('data-lang', 'ru');
    script.setAttribute('data-onauth', 'handleTelegramAuth(user)');
    script.async = true;
    
    const container = document.getElementById('telegram-login-container');
    if (container) {
      container.innerHTML = '';
      container.appendChild(script);
    }

    // Очистка
    return () => {
      delete window.handleTelegramAuth;
    };
  }, [loginWithTelegram, navigate, showNotification]);

  return (
    <div style={{ 
      minHeight: '60vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    }}>
      <div className="form-container" style={{ maxWidth: '400px' }}>
        <h1 className="form-title">Добро пожаловать в Visor Market</h1>
        
        <p style={{ textAlign: 'center', marginBottom: '2rem', color: 'var(--gray)' }}>
          Войдите через Telegram, чтобы начать торговлю игровой валютой
        </p>

        {/* Контейнер для Telegram Widget */}
        <div id="telegram-login-container" style={{ 
          display: 'flex', 
          justifyContent: 'center', 
          marginBottom: '1rem',
          minHeight: '60px'
        }}></div>

        {/* Информация для пользователя */}
        <div style={{ 
          marginTop: '2rem', 
          textAlign: 'center',
          fontSize: '0.9rem',
          color: 'var(--gray)'
        }}>
          <p>🔐 Безопасный вход через Telegram</p>
          <p>⭐ Отзывы и рейтинг пользователей</p>
          <p>💰 Комиссия платформы 5%</p>
          <p>🛡️ Все сделки защищены</p>
        </div>
      </div>
    </div>
  );
}

export default Login;