import React, { useState } from 'react';
import { useSearchParams } from 'react-router-dom';
import ListingCard from '../components/ListingCard';
import TransactionModal from '../components/TransactionModal';
import ChatModal from '../components/ChatModal';
import { useUser } from '../context/UserContext';
import { useNotification } from '../components/Notification';

function Buy() {
  const [searchParams] = useSearchParams();
  const [gameFilter, setGameFilter] = useState(searchParams.get('game') || '');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [sortBy, setSortBy] = useState('price_asc');
  const [isSearchFocused, setIsSearchFocused] = useState(false);
  const [selectedListing, setSelectedListing] = useState(null);
  const [selectedChatListing, setSelectedChatListing] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const { showNotification } = useNotification();
  const { users, currentUser, allListings, categories } = useUser();

  // Получаем все уникальные категории из объявлений
  const availableCategories = [...new Set(allListings
    .filter(l => l.type === 'sell' && l.status === 'active')
    .map(l => l.category)
    .filter(Boolean)
  )];

  // Фильтруем только объявления о продаже
  const listings = allListings.filter(l => l.type === 'sell' && l.status === 'active');

  // Фильтрация и сортировка
  const filteredListings = listings
    .filter(listing => {
      // Фильтр по игре
      if (gameFilter && !listing.game.toLowerCase().includes(gameFilter.toLowerCase())) {
        return false;
      }
      // Фильтр по категории
      if (categoryFilter && listing.category !== categoryFilter) {
        return false;
      }
      return true;
    })
    .sort((a, b) => {
      const pricePerUnitA = a.price / a.amount;
      const pricePerUnitB = b.price / b.amount;
      
      if (sortBy === 'price_asc') return pricePerUnitA - pricePerUnitB;
      if (sortBy === 'price_desc') return pricePerUnitB - pricePerUnitA;
      if (sortBy === 'amount_desc') return b.amount - a.amount;
      return 0;
    });

  const handleBuy = (listing) => {
    if (!currentUser) {
      showNotification('Сначала войдите в систему', 'error');
      return;
    }
    setSelectedListing(listing);
    setIsModalOpen(true);
  };

  const handleChat = (listing) => {
    if (!currentUser) {
      showNotification('Сначала войдите в систему', 'error');
      return;
    }
    
    const seller = users.find(u => u.username === listing.seller);
    if (!seller) {
      showNotification('Продавец не найден', 'error');
      return;
    }

    setSelectedChatListing({
      ...listing,
      seller: seller,
      sellerId: seller.id
    });
    setIsChatOpen(true);
  };

  const handleClearSearch = () => {
    setGameFilter('');
    setCategoryFilter('');
  };

  return (
    <div>
      <h1 className="section-title">Купить игровую валюту</h1>
      
      {/* Красивый поиск с фильтрами */}
      <div className="search-section">
        <div className="search-container" style={{ maxWidth: '800px' }}>
          <div className="search-wrapper">
            <span className="search-icon">🔍</span>
            <input
              type="text"
              placeholder="Поиск по названию игры..."
              className="search-input"
              value={gameFilter}
              onChange={(e) => setGameFilter(e.target.value)}
              onFocus={() => setIsSearchFocused(true)}
              onBlur={() => setIsSearchFocused(false)}
            />
            {gameFilter && (
              <button 
                className={`search-clear ${gameFilter ? 'visible' : ''}`}
                onClick={() => setGameFilter('')}
              >
                ✕
              </button>
            )}
          </div>

          {/* Дополнительные фильтры */}
          <div style={{ 
            display: 'flex', 
            gap: '1rem',
            marginTop: '1rem',
            flexWrap: 'wrap'
          }}>
            {/* Фильтр по категориям */}
            {availableCategories.length > 0 && (
              <select 
                className="search-select"
                value={categoryFilter}
                onChange={(e) => setCategoryFilter(e.target.value)}
                style={{ minWidth: '150px' }}
              >
                <option value="">Все категории</option>
                {availableCategories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            )}

            <select 
              className="search-select"
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value)}
              style={{ minWidth: '150px' }}
            >
              <option value="price_asc">Цена ↑ (дешевле)</option>
              <option value="price_desc">Цена ↓ (дороже)</option>
              <option value="amount_desc">Количество ↓</option>
            </select>
          </div>

          {/* Статистика поиска */}
          {(gameFilter || categoryFilter) && (
            <div className="search-stats">
              Найдено <strong>{filteredListings.length}</strong> объявлений
            </div>
          )}
        </div>
      </div>

      {/* Результаты */}
      {filteredListings.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--gray)' }}>
          <p style={{ fontSize: '3rem', marginBottom: '1rem' }}>🔍</p>
          <p>Нет активных объявлений</p>
          {(gameFilter || categoryFilter) && (
            <button 
              className="btn btn-outline" 
              onClick={handleClearSearch}
              style={{ marginTop: '1rem' }}
            >
              Очистить фильтры
            </button>
          )}
          <p style={{ marginTop: '2rem' }}>
            <a href="#/sell" className="btn btn-primary" style={{ width: 'auto' }}>
              💰 Создать объявление
            </a>
          </p>
        </div>
      ) : (
        <div className="listings-grid">
          {filteredListings.map(listing => (
            <ListingCard 
              key={listing.id} 
              listing={listing} 
              onAction={handleBuy}
              onChat={handleChat}
            />
          ))}
        </div>
      )}

      {/* Модалка покупки */}
      {selectedListing && (
        <TransactionModal
          isOpen={isModalOpen}
          onClose={() => {
            setIsModalOpen(false);
            setSelectedListing(null);
          }}
          listing={selectedListing}
          type="buy"
        />
      )}

      {/* Модалка чата */}
      {selectedChatListing && selectedChatListing.seller && (
        <ChatModal
          isOpen={isChatOpen}
          onClose={() => {
            setIsChatOpen(false);
            setSelectedChatListing(null);
          }}
          seller={selectedChatListing.seller}
          buyer={currentUser}
          listing={selectedChatListing}
        />
      )}
    </div>
  );
}

export default Buy;