import React, { useState, useEffect, useRef } from 'react';
import { useUser } from '../context/UserContext';
import { useNotification } from './Notification';

function SupportChat({ isOpen, onClose, ticket }) {
  const { currentUser, addTicketMessage, closeSupportTicket, isSupport } = useUser();
  const { showNotification } = useNotification();
  const [messages, setMessages] = useState(ticket?.messages || []);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (ticket) {
      setMessages(ticket.messages || []);
    }
  }, [ticket]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!newMessage.trim() || !ticket) return;

    const result = await addTicketMessage(ticket.id, newMessage);
    
    if (result.success) {
      setNewMessage('');
    } else {
      showNotification('Ошибка отправки сообщения', 'error');
    }
  };

  const handleCloseTicket = async () => {
    if (window.confirm('Закрыть обращение?')) {
      await closeSupportTicket(ticket.id);
      showNotification('Обращение закрыто', 'success');
      onClose();
    }
  };

  if (!isOpen || !ticket) return null;

  const canClose = isSupport() || ticket.userId === currentUser?.id;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div 
        className="modal" 
        onClick={e => e.stopPropagation()}
        style={{ 
          maxWidth: '500px', 
          height: '80vh', 
          display: 'flex', 
          flexDirection: 'column',
          padding: 0,
          overflow: 'hidden'
        }}
      >
        {/* Шапка чата поддержки */}
        <div style={{
          padding: '1rem',
          borderBottom: '1px solid var(--border)',
          display: 'flex',
          alignItems: 'center',
          gap: '1rem',
          background: 'var(--gradient)',
          color: 'white'
        }}>
          <span className="modal-close" onClick={onClose} style={{ color: 'white' }}>&times;</span>
          
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flex: 1 }}>
            <div style={{ 
              width: '40px', 
              height: '40px', 
              borderRadius: '50%',
              background: 'white',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: '1.2rem'
            }}>
              🛟
            </div>
            <div>
              <div style={{ fontWeight: 'bold' }}>Техподдержка</div>
              <div style={{ fontSize: '0.8rem', opacity: 0.9 }}>
                Обращение #{ticket.id ? ticket.id.slice(-6) : 'новое'}
              </div>
            </div>
          </div>

          {canClose && ticket.status === 'open' && (
            <button
              onClick={handleCloseTicket}
              style={{
                background: 'rgba(255,255,255,0.2)',
                border: 'none',
                color: 'white',
                padding: '0.3rem 0.8rem',
                borderRadius: '4px',
                cursor: 'pointer'
              }}
            >
              Закрыть
            </button>
          )}
        </div>

        {/* Информация о тикете */}
        <div style={{
          padding: '0.5rem 1rem',
          background: '#fff3cd',
          fontSize: '0.8rem',
          borderBottom: '1px solid #ffeeba'
        }}>
          <strong>Тема:</strong> {ticket.description || 'Обращение в поддержку'}
          {ticket.status === 'closed' && (
            <span style={{ marginLeft: '1rem', color: 'var(--gray)' }}>
              • Обращение закрыто
            </span>
          )}
        </div>

        {/* Сообщения */}
        <div 
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: '1rem',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.5rem',
            background: '#f8f9fa'
          }}
        >
          {messages.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
              <p>Нет сообщений. Напишите что-нибудь...</p>
            </div>
          ) : (
            messages.map((msg, index) => {
              const isMyMessage = msg.from === currentUser?.id;
              const sender = msg.from === 'system' ? 'Система' : 
                            (isMyMessage ? 'Вы' : 'Поддержка');
              
              return (
                <div
                  key={index}
                  style={{
                    display: 'flex',
                    justifyContent: isMyMessage ? 'flex-end' : 'flex-start',
                    marginBottom: index === messages.length - 1 ? 0 : '0.5rem'
                  }}
                >
                  <div
                    style={{
                      maxWidth: '70%',
                      background: msg.from === 'system' ? '#e9ecef' :
                                  isMyMessage ? 'var(--primary)' : 'white',
                      color: msg.from === 'system' ? 'var(--dark)' :
                             isMyMessage ? 'white' : 'var(--dark)',
                      padding: '0.75rem',
                      borderRadius: '12px',
                      borderBottomRightRadius: isMyMessage ? '4px' : '12px',
                      borderBottomLeftRadius: isMyMessage ? '12px' : '4px',
                      boxShadow: '0 1px 2px rgba(0,0,0,0.1)',
                      fontSize: '0.9rem'
                    }}
                  >
                    <div style={{ fontWeight: 'bold', fontSize: '0.8rem', marginBottom: '0.25rem' }}>
                      {sender}
                    </div>
                    <div style={{ wordBreak: 'break-word' }}>{msg.text}</div>
                    <div style={{
                      fontSize: '0.7rem',
                      marginTop: '0.25rem',
                      opacity: 0.7,
                      textAlign: 'right'
                    }}>
                      {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString() : ''}
                    </div>
                  </div>
                </div>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Форма отправки (только для открытых тикетов) */}
        {ticket.status === 'open' && (
          <form onSubmit={handleSendMessage} style={{
            padding: '1rem',
            borderTop: '1px solid var(--border)',
            background: 'white',
            display: 'flex',
            gap: '0.5rem'
          }}>
            <input
              type="text"
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              placeholder="Напишите сообщение..."
              style={{
                flex: 1,
                padding: '0.75rem',
                border: '1px solid var(--border)',
                borderRadius: '20px',
                outline: 'none',
                fontSize: '0.95rem'
              }}
              autoFocus
            />
            <button
              type="submit"
              disabled={!newMessage.trim()}
              style={{
                background: 'var(--primary)',
                color: 'white',
                border: 'none',
                borderRadius: '50%',
                width: '45px',
                height: '45px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                cursor: newMessage.trim() ? 'pointer' : 'not-allowed',
                opacity: newMessage.trim() ? 1 : 0.5
              }}
            >
              📤
            </button>
          </form>
        )}
      </div>
    </div>
  );
}

export default SupportChat;