import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import { useNotification } from '../components/Notification';
import ChatModal from '../components/ChatModal';

function Messages() {
  const navigate = useNavigate();
  const { currentUser, getUserChats, users, markAsRead, getMessages } = useUser();
  const { showNotification } = useNotification();
  const [chatsList, setChatsList] = useState([]);
  const [selectedChat, setSelectedChat] = useState(null);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!currentUser) {
      navigate('/login');
      return;
    }

    loadChats();
  }, [currentUser, navigate]);

  const loadChats = () => {
    setLoading(true);
    const chats = getUserChats(currentUser.id);
    // Сортируем по последнему сообщению
    const sortedChats = chats.sort((a, b) => {
      const aTime = a.updatedAt || a.createdAt;
      const bTime = b.updatedAt || b.createdAt;
      return new Date(bTime) - new Date(aTime);
    });
    setChatsList(sortedChats);
    setLoading(false);
  };

  const handleOpenChat = async (chat) => {
    // Получаем полные данные чата с сообщениями
    const fullChat = {
      ...chat,
      messages: getMessages(chat.id)
    };
    setSelectedChat(fullChat);
    setIsChatOpen(true);
    await markAsRead(chat.id);
    // Обновляем список чатов после прочтения
    setTimeout(loadChats, 500);
  };

  const getOtherParticipant = (chat) => {
    const otherUserId = chat.participants?.find(id => id !== currentUser?.id);
    return users.find(u => u.id === otherUserId);
  };

  const getLastMessage = (chat) => {
    if (!chat.messages || chat.messages.length === 0) return 'Нет сообщений';
    const lastMsg = chat.messages[chat.messages.length - 1];
    return lastMsg.text.length > 30 ? lastMsg.text.substring(0, 30) + '...' : lastMsg.text;
  };

  const getLastMessageTime = (chat) => {
    if (!chat.messages || chat.messages.length === 0) return '';
    const lastMsg = chat.messages[chat.messages.length - 1];
    const date = new Date(lastMsg.timestamp);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    if (date.toDateString() === today.toDateString()) {
      return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
    } else if (date.toDateString() === yesterday.toDateString()) {
      return 'Вчера';
    } else {
      return date.toLocaleDateString('ru-RU', { day: '2-digit', month: '2-digit' });
    }
  };

  const getUnreadCount = (chat) => {
    return chat.messages?.filter(m => !m.read && m.toUserId === currentUser?.id).length || 0;
  };

  if (!currentUser) return null;

  return (
    <div>
      <h1 className="section-title">Сообщения</h1>

      {loading ? (
        <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--gray)' }}>
          <p>Загрузка...</p>
        </div>
      ) : chatsList.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--gray)' }}>
          <p style={{ fontSize: '3rem', marginBottom: '1rem' }}>💬</p>
          <p>У вас пока нет сообщений</p>
          <p style={{ marginTop: '1rem', fontSize: '0.9rem' }}>
            Начните диалог с продавцом на странице покупки
          </p>
          <button
            className="btn btn-primary"
            onClick={() => navigate('/buy')}
            style={{ marginTop: '2rem', width: 'auto' }}
          >
            Купить валюту
          </button>
        </div>
      ) : (
        <div style={{ marginTop: '1rem' }}>
          {chatsList.map(chat => {
            const otherUser = getOtherParticipant(chat);
            const unread = getUnreadCount(chat);
            const lastMessage = getLastMessage(chat);
            const lastTime = getLastMessageTime(chat);

            if (!otherUser) return null;

            return (
              <div
                key={chat.id}
                className="listing-card"
                onClick={() => handleOpenChat(chat)}
                style={{
                  marginBottom: '1rem',
                  cursor: 'pointer',
                  borderLeft: unread > 0 ? '4px solid var(--primary)' : 'none',
                  background: unread > 0 ? '#f0f4ff' : 'white',
                  transition: 'all 0.2s',
                  padding: '1rem'
                }}
              >
                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                  <div className="avatar" style={{ 
                    width: '50px', 
                    height: '50px',
                    border: otherUser?.role === 'support' ? '2px solid var(--success)' : 
                            otherUser?.role === 'admin' ? '2px solid var(--primary)' : 'none',
                    position: 'relative'
                  }}>
                    {otherUser?.username?.[0]?.toUpperCase() || '?'}
                    {otherUser?.role === 'support' && (
                      <div style={{
                        position: 'absolute',
                        bottom: '-4px',
                        right: '-4px',
                        background: 'var(--success)',
                        color: 'white',
                        borderRadius: '50%',
                        width: '18px',
                        height: '18px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '10px',
                        border: '2px solid white'
                      }}>
                        🛟
                      </div>
                    )}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <h3 style={{ margin: 0, fontSize: '1rem' }}>
                        {otherUser?.firstName} {otherUser?.lastName}
                        {otherUser?.role === 'support' && ' 🛟'}
                        {otherUser?.role === 'admin' && ' 👑'}
                      </h3>
                      <span style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>
                        {lastTime}
                      </span>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0.25rem' }}>
                      <span style={{ 
                        color: unread > 0 ? 'var(--dark)' : 'var(--gray)',
                        fontWeight: unread > 0 ? '600' : '400',
                        fontSize: '0.9rem'
                      }}>
                        {lastMessage}
                      </span>
                      {unread > 0 && (
                        <span style={{
                          background: 'var(--primary)',
                          color: 'white',
                          borderRadius: '50%',
                          width: '22px',
                          height: '22px',
                          fontSize: '12px',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          fontWeight: 'bold'
                        }}>
                          {unread}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {selectedChat && (
        <ChatModal
          isOpen={isChatOpen}
          onClose={() => {
            setIsChatOpen(false);
            setSelectedChat(null);
            // Обновляем список чатов после закрытия
            setTimeout(loadChats, 500);
          }}
          seller={getOtherParticipant(selectedChat)}
          buyer={currentUser}
          listing={selectedChat}
        />
      )}
    </div>
  );
}

export default Messages;