import React, { useState } from 'react';
import { useUser } from '../context/UserContext';
import { useNotification } from '../components/Notification';

function Listings() {
  const { currentUser, userListings, cancelListing } = useUser();
  const { showNotification } = useNotification();
  const [filter, setFilter] = useState('all');
  const [processingId, setProcessingId] = useState(null);

  // Проверяем, что пользователь авторизован
  if (!currentUser) {
    return (
      <div style={{ textAlign: 'center', padding: '3rem' }}>
        <h2>Требуется авторизация</h2>
        <p>Войдите в систему, чтобы просмотреть свои объявления</p>
        <a href="#/login" className="btn btn-primary" style={{ marginTop: '1rem' }}>
          Войти
        </a>
      </div>
    );
  }

  // Фильтрация объявлений
  const filteredListings = userListings.filter(listing => {
    if (filter === 'active') return listing.status === 'active';
    if (filter === 'cancelled') return listing.status === 'cancelled';
    return true;
  });

  const handleCancel = (listing) => {
    if (window.confirm('Отменить объявление?')) {
      setProcessingId(listing.id);
      
      setTimeout(() => {
        cancelListing(listing.id);
        showNotification('🗑️ Объявление успешно снято с продажи', 'info', 3000);
        setProcessingId(null);
      }, 300);
    }
  };

  return (
    <div>
      <h1 className="section-title">Мои объявления</h1>

      {/* Фильтры */}
      <div className="search-bar">
        <select 
          className="search-select"
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
        >
          <option value="all">Все объявления</option>
          <option value="active">Активные</option>
          <option value="cancelled">Отмененные</option>
        </select>
      </div>

      {/* Список объявлений */}
      {filteredListings.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--gray)' }}>
          <p style={{ fontSize: '3rem', marginBottom: '1rem' }}>📭</p>
          <p>У вас нет объявлений</p>
          <a href="#/sell" className="btn btn-primary" style={{ width: 'auto', marginTop: '1rem' }}>
            Создать объявление
          </a>
        </div>
      ) : (
        <div className="listings-grid">
          {filteredListings.map(listing => (
            <div key={listing.id} className="listing-card">
              <div className="listing-header">
                <span className="listing-game">{listing.game}</span>
                <span className={`listing-type ${listing.type === 'buy' ? 'type-buy' : 'type-sell'}`}>
                  {listing.type === 'buy' ? '🛒 Покупка' : '💰 Продажа'}
                </span>
              </div>
              
              {listing.category && (
                <div style={{ 
                  fontSize: '0.8rem', 
                  color: 'var(--primary)', 
                  marginBottom: '0.5rem',
                  padding: '0.2rem 0.5rem',
                  background: 'rgba(108, 92, 231, 0.1)',
                  borderRadius: '4px',
                  display: 'inline-block'
                }}>
                  {listing.category}
                </div>
              )}
              
              <div className="listing-amount">
                {listing.amount} {listing.currency}
              </div>
              
              <div className="listing-price">
                Цена: <span>{listing.price} ₽</span>
              </div>

              <div style={{ margin: '0.5rem 0', fontSize: '0.9rem' }}>
                Статус: {
                  listing.status === 'active' 
                    ? <span style={{ color: 'var(--success)' }}>✓ Активно</span>
                    : <span style={{ color: 'var(--gray)' }}>✗ Отменено</span>
                }
              </div>

              {listing.status === 'active' && (
                <button 
                  className="btn btn-outline"
                  onClick={() => handleCancel(listing)}
                  disabled={processingId === listing.id}
                  style={{
                    opacity: processingId === listing.id ? 0.5 : 1,
                    cursor: processingId === listing.id ? 'wait' : 'pointer'
                  }}
                >
                  {processingId === listing.id ? 'Отмена...' : 'Отменить'}
                </button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export default Listings;