import React, { useState, useEffect } from 'react';

// Компонент отдельного уведомления
function NotificationItem({ id, message, type, duration, onClose }) {
  const [isVisible, setIsVisible] = useState(true);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsVisible(false);
      setTimeout(() => onClose(id), 300); // Даем время на анимацию исчезновения
    }, duration);

    return () => clearTimeout(timer);
  }, [duration, id, onClose]);

  if (!isVisible) return null;

  return (
    <div 
      className={`notification ${type}`}
      style={{
        animation: 'slideIn 0.3s, fadeOut 0.3s 2.7s forwards',
        marginBottom: '10px',
        position: 'relative',
        cursor: 'pointer'
      }}
      onClick={() => {
        setIsVisible(false);
        setTimeout(() => onClose(id), 300);
      }}
    >
      {message}
    </div>
  );
}

// Хук для управления уведомлениями
export function useNotification() {
  const [notifications, setNotifications] = useState([]);

  const showNotification = (message, type = 'info', duration = 3000) => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, message, type, duration }]);
    return id;
  };

  const removeNotification = (id) => {
    setNotifications(prev => prev.filter(notif => notif.id !== id));
  };

  const NotificationComponent = (
    <div style={{
      position: 'fixed',
      top: '20px',
      right: '20px',
      zIndex: 2000,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'flex-end',
      pointerEvents: 'none'
    }}>
      <div style={{ pointerEvents: 'auto', width: '300px' }}>
        {notifications.map(notif => (
          <NotificationItem
            key={notif.id}
            id={notif.id}
            message={notif.message}
            type={notif.type}
            duration={notif.duration}
            onClose={removeNotification}
          />
        ))}
      </div>
    </div>
  );

  return {
    showNotification,
    NotificationComponent
  };
}