import React from 'react';
import { useUser } from '../context/UserContext';

function ListingCard({ listing, onAction, onChat }) {
  const { currentUser } = useUser();

  const handleClick = () => {
    onAction?.(listing);
  };

  const handleChat = (e) => {
    e.stopPropagation();
    if (!currentUser) {
      alert('Войдите в систему, чтобы написать продавцу');
      return;
    }
    onChat?.(listing);
  };

  return (
    <div className="listing-card">
      <div className="listing-header">
        <span className="listing-game">{listing.game}</span>
        <span className={`listing-type ${listing.type === 'buy' ? 'type-buy' : 'type-sell'}`}>
          {listing.type === 'buy' ? 'Покупка' : 'Продажа'}
        </span>
      </div>
      
      {/* Отображение подкатегории */}
      {listing.category && (
        <div style={{ 
          fontSize: '0.8rem', 
          color: 'var(--primary)', 
          marginBottom: '0.5rem',
          padding: '0.2rem 0.5rem',
          background: 'rgba(108, 92, 231, 0.1)',
          borderRadius: '4px',
          display: 'inline-block'
        }}>
          📁 {listing.category}
        </div>
      )}
      
      <div className="listing-amount">
        {listing.amount.toLocaleString()} {listing.currency}
      </div>
      
      <div className="listing-price">
        {listing.price} ₽ <span>за всё</span>
      </div>

      <div className="listing-seller">
        <div className="seller-avatar">
          {listing.seller[0]}
        </div>
        <span>{listing.seller}</span>
      </div>

      <div style={{ 
        display: 'flex', 
        justifyContent: 'space-between',
        fontSize: '0.8rem', 
        color: 'var(--gray)', 
        marginBottom: '0.5rem' 
      }}>
        <span>Комиссия: {Math.floor(listing.price * 0.05)} ₽</span>
        <span>Продавец получит: {listing.price - Math.floor(listing.price * 0.05)} ₽</span>
      </div>

      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button 
          className="btn btn-outline"
          onClick={handleChat}
          style={{ flex: 1 }}
        >
          💬 Чат с продавцом
        </button>
        <button 
          className={`btn ${listing.type === 'sell' ? 'btn-primary' : 'btn-outline'}`}
          onClick={handleClick}
          style={{ flex: 2 }}
        >
          {listing.type === 'sell' ? 'Купить' : 'Продать'}
        </button>
      </div>
    </div>
  );
}

export default ListingCard;