import { getData, pushData } from '../firebase';

export async function initFirebaseData() {
  try {
    // Проверяем, есть ли уже игры
    const gamesSnapshot = await getData('games');
    
    if (!gamesSnapshot.exists()) {
      // Добавляем начальные игры
      const games = [
        { name: 'World of Warcraft', icon: '⚔️', listings: 0, minPrice: 0, active: true },
        { name: 'CS:GO', icon: '🔫', listings: 0, minPrice: 0, active: true },
        { name: 'Dota 2', icon: '🏆', listings: 0, minPrice: 0, active: true },
        { name: 'Genshin Impact', icon: '⭐', listings: 0, minPrice: 0, active: true },
        { name: 'Fortnite', icon: '🛡️', listings: 0, minPrice: 0, active: true },
        { name: 'Valorant', icon: '🎯', listings: 0, minPrice: 0, active: true },
        { name: 'Lost Ark', icon: '⚓', listings: 0, minPrice: 0, active: true },
        { name: 'Lineage 2', icon: '👑', listings: 0, minPrice: 0, active: true },
        { name: 'Aion', icon: '🦋', listings: 0, minPrice: 0, active: true },
        { name: 'BDO', icon: '🗡️', listings: 0, minPrice: 0, active: true }
      ];

      for (const game of games) {
        await pushData('games', game);
      }
      console.log('✅ Игры добавлены в Firebase');
    }

    // Проверяем, есть ли админ
    const usersSnapshot = await getData('users');
    
    if (!usersSnapshot.exists()) {
      // Добавляем админа
      const admin = {
        telegramId: 802498337,
        username: 'admin',
        firstName: 'Admin',
        lastName: 'Visor',
        registrationDate: new Date().toISOString(),
        role: 'admin',
        stats: {
          totalTrades: 0,
          positiveReviews: 0,
          negativeReviews: 0,
          avgRating: 0
        }
      };
      
      await pushData('users', admin);
      console.log('✅ Админ добавлен в Firebase');
    }
  } catch (error) {
    console.error('❌ Ошибка инициализации Firebase данных:', error);
  }
}