import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import GameCard from '../components/GameCard';

function Home() {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');
  const [isSearchFocused, setIsSearchFocused] = useState(false);
  const { games, getGames, allListings, users, isAdmin } = useUser();
  
  const [gamesList, setGamesList] = useState([]);
  const [stats, setStats] = useState({
    totalListings: 0,
    totalUsers: 0,
    completedTrades: 0
  });

  // Загружаем игры и считаем статистику
  useEffect(() => {
    const loadedGames = getGames();
    
    const updatedGames = loadedGames.map(game => {
      const gameListings = allListings.filter(
        l => l.game === game.name && l.status === 'active'
      ).length;
      
      const minPrice = allListings
        .filter(l => l.game === game.name && l.status === 'active')
        .reduce((min, l) => Math.min(min, l.price / l.amount), Infinity);
      
      return {
        ...game,
        listings: gameListings,
        minPrice: minPrice !== Infinity ? Math.floor(minPrice) : 0
      };
    });
    
    setGamesList(updatedGames);

    const activeListings = allListings.filter(l => l.status === 'active').length;
    const totalUsers = users.length;
    const completedTrades = allListings.filter(l => l.status === 'completed').length;

    setStats({
      totalListings: activeListings,
      totalUsers: totalUsers,
      completedTrades: completedTrades
    });
  }, [getGames, allListings, users]);

  // Фильтрация игр по поиску
  const filteredGames = gamesList.filter(game =>
    game.name?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleClearSearch = () => {
    setSearchTerm('');
  };

  return (
    <div>
      {/* Герой-секция */}
      <section className="hero">
        <h1>Visor Market</h1>
        <p>Безопасная торговля игровой валютой с комиссией 5%</p>
        
        <div className="stats">
          <div className="stat-item">
            <div className="stat-value">{stats.totalListings}</div>
            <div className="stat-label">Активных объявлений</div>
          </div>
          <div className="stat-item">
            <div className="stat-value">{stats.totalUsers.toLocaleString()}</div>
            <div className="stat-label">Пользователей</div>
          </div>
          <div className="stat-item">
            <div className="stat-value">{stats.completedTrades.toLocaleString()}</div>
            <div className="stat-label">Завершенных сделок</div>
          </div>
        </div>

        <div className="hero-buttons">
          <a href="#/buy" className="btn-hero">Купить валюту</a>
          <a href="#/sell" className="btn-hero-outline">Продать валюту</a>
        </div>
      </section>

      {/* Красивый поиск */}
      <div className="search-section">
        <div className="search-container">
          <div className={`search-wrapper ${isSearchFocused ? 'focused' : ''}`}>
            <span className="search-icon">🔍</span>
            <input
              type="text"
              placeholder="Поиск игр..."
              className="search-input"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onFocus={() => setIsSearchFocused(true)}
              onBlur={() => setIsSearchFocused(false)}
            />
            {searchTerm && (
              <button 
                className={`search-clear ${searchTerm ? 'visible' : ''}`}
                onClick={handleClearSearch}
              >
                ✕
              </button>
            )}
          </div>
          
          {searchTerm && (
            <div className="search-stats">
              Найдено <strong>{filteredGames.length}</strong> игр
            </div>
          )}
        </div>
      </div>

      {/* Заголовок */}
      <h2 className="section-title">Популярные игры</h2>

      {/* Сетка игр */}
      {gamesList.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--gray)' }}>
          <p style={{ fontSize: '3rem', marginBottom: '1rem' }}>🎮</p>
          <p>Игры пока не добавлены</p>
          <p style={{ marginTop: '1rem', fontSize: '0.9rem' }}>
            {isAdmin() 
              ? 'Добавьте игры через админ-панель' 
              : 'Администратор добавит игры в ближайшее время'}
          </p>
          {isAdmin() && (
            <a href="#/admin" className="btn btn-primary" style={{ marginTop: '1rem', width: 'auto' }}>
              ➕ Добавить игры
            </a>
          )}
        </div>
      ) : (
        <>
          {filteredGames.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
              <p style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>🔍</p>
              <p>Игры не найдены</p>
              <button 
                className="btn btn-outline" 
                onClick={handleClearSearch}
                style={{ marginTop: '1rem' }}
              >
                Очистить поиск
              </button>
            </div>
          ) : (
            <div className="games-grid">
              {filteredGames.map(game => (
                <GameCard 
                  key={game.id} 
                  game={game}
                  onClick={() => navigate(`/buy?game=${encodeURIComponent(game.name)}`)}
                />
              ))}
            </div>
          )}
        </>
      )}

      {/* Подсказка для пользователей */}
      {stats.totalListings === 0 && gamesList.length > 0 && (
        <div style={{ 
          marginTop: '3rem', 
          padding: '1.5rem', 
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          color: 'white',
          borderRadius: '12px',
          textAlign: 'center'
        }}>
          <h3 style={{ marginBottom: '1rem' }}>🚀 Начните торговлю прямо сейчас!</h3>
          <p style={{ marginBottom: '1rem', opacity: 0.9 }}>
            Пока нет активных объявлений. Создайте своё объявление о продаже!
          </p>
          <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center', flexWrap: 'wrap' }}>
            <a href="#/sell" className="btn-hero" style={{ background: 'white', color: 'var(--primary)' }}>
              💰 Продать валюту
            </a>
            <a href="#/buy" className="btn-hero-outline" style={{ borderColor: 'white', color: 'white' }}>
              🛒 Купить валюту
            </a>
          </div>
        </div>
      )}
    </div>
  );
}

export default Home;