import React, { useState, useEffect, useRef } from 'react';
import { useUser } from '../context/UserContext';
import { useNotification } from './Notification';

function ChatModal({ isOpen, onClose, seller, buyer, listing }) {
  const { currentUser, sendMessage, getMessages, markAsRead, getOrCreateChat } = useUser();
  const { showNotification } = useNotification();
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [chatId, setChatId] = useState(null);
  const messagesEndRef = useRef(null);
  const chatContainerRef = useRef(null);

  // Создаем или получаем chatId при открытии
  useEffect(() => {
    const initChat = async () => {
      if (isOpen && currentUser && seller && listing) {
        const id = await getOrCreateChat(listing.id, currentUser.id, seller.id);
        setChatId(id);
        loadMessages(id);
      }
    };
    initChat();
  }, [isOpen, currentUser, seller, listing]);

  // Загружаем сообщения
  const loadMessages = (id) => {
    setLoading(true);
    const chatMessages = getMessages(id);
    setMessages(chatMessages);
    setLoading(false);
    
    // Отмечаем как прочитанные
    if (id) {
      markAsRead(id);
    }
  };

  // Автоскролл к последнему сообщению
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    if (!newMessage.trim() || !chatId) return;

    const messageData = {
      id: Date.now(),
      chatId: chatId,
      fromUserId: currentUser.id,
      toUserId: seller.id,
      listingId: listing.id,
      text: newMessage.trim(),
      timestamp: new Date().toISOString(),
      read: false
    };

    const result = await sendMessage(messageData);
    
    if (result.success) {
      setMessages(prev => [...prev, messageData]);
      setNewMessage('');

      if (window.Telegram && window.Telegram.WebApp) {
        window.Telegram.WebApp.HapticFeedback.impactOccurred('light');
      }
    } else {
      showNotification('Ошибка отправки сообщения', 'error');
    }
  };

  const formatTime = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDate = (timestamp) => {
    const date = new Date(timestamp);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    if (date.toDateString() === today.toDateString()) {
      return 'Сегодня';
    } else if (date.toDateString() === yesterday.toDateString()) {
      return 'Вчера';
    } else {
      return date.toLocaleDateString('ru-RU');
    }
  };

  // Группируем сообщения по дням
  const groupedMessages = messages.reduce((groups, message) => {
    const date = formatDate(message.timestamp);
    if (!groups[date]) {
      groups[date] = [];
    }
    groups[date].push(message);
    return groups;
  }, {});

  if (!isOpen) return null;

  const otherUser = currentUser?.id === seller?.id ? buyer : seller;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div 
        className="modal" 
        onClick={e => e.stopPropagation()}
        style={{ 
          maxWidth: '500px', 
          height: '80vh', 
          display: 'flex', 
          flexDirection: 'column',
          padding: 0,
          overflow: 'hidden'
        }}
      >
        {/* Шапка чата */}
        <div style={{
          padding: '1rem',
          borderBottom: '1px solid var(--border)',
          display: 'flex',
          alignItems: 'center',
          gap: '1rem',
          background: 'white'
        }}>
          <span className="modal-close" onClick={onClose} style={{ position: 'static' }}>&times;</span>
          
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', flex: 1 }}>
            <div 
              className="avatar" 
              style={{ 
                width: '40px', 
                height: '40px',
                border: otherUser?.role === 'support' ? '2px solid var(--success)' : 
                        otherUser?.role === 'admin' ? '2px solid var(--primary)' : 'none'
              }}
            >
              {otherUser?.username?.[0]?.toUpperCase() || '?'}
            </div>
            <div>
              <div style={{ fontWeight: 'bold' }}>
                {otherUser?.firstName || 'Пользователь'} {otherUser?.lastName || ''}
                {otherUser?.role === 'support' && ' 🛟'}
                {otherUser?.role === 'admin' && ' 👑'}
              </div>
              <div style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>
                @{otherUser?.username || 'username'}
              </div>
            </div>
          </div>

          {/* Информация о товаре */}
          {listing && (
            <div style={{
              background: 'var(--light)',
              padding: '0.5rem',
              borderRadius: '8px',
              fontSize: '0.8rem',
              maxWidth: '150px'
            }}>
              <div><strong>{listing.game}</strong></div>
              <div>{listing.amount} {listing.currency}</div>
            </div>
          )}
        </div>

        {/* Сообщения */}
        <div 
          ref={chatContainerRef}
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: '1rem',
            display: 'flex',
            flexDirection: 'column',
            gap: '0.5rem',
            background: '#f8f9fa'
          }}
        >
          {loading ? (
            <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
              Загрузка сообщений...
            </div>
          ) : messages.length === 0 ? (
            <div style={{ 
              textAlign: 'center', 
              padding: '2rem', 
              color: 'var(--gray)',
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              gap: '1rem'
            }}>
              <div style={{ fontSize: '3rem' }}>💬</div>
              <p>Начните диалог с {otherUser?.firstName || 'продавцом'}</p>
            </div>
          ) : (
            Object.entries(groupedMessages).map(([date, dateMessages]) => (
              <div key={date}>
                {/* Разделитель по дням */}
                <div style={{
                  textAlign: 'center',
                  margin: '1rem 0',
                  position: 'relative'
                }}>
                  <span style={{
                    background: '#f8f9fa',
                    padding: '0 1rem',
                    color: 'var(--gray)',
                    fontSize: '0.8rem',
                    position: 'relative',
                    zIndex: 1
                  }}>
                    {date}
                  </span>
                  <div style={{
                    position: 'absolute',
                    top: '50%',
                    left: 0,
                    right: 0,
                    height: '1px',
                    background: '#e5e7eb',
                    zIndex: 0
                  }} />
                </div>

                {dateMessages.map((message, index) => {
                  const isMyMessage = message.fromUserId === currentUser?.id;
                  
                  return (
                    <div
                      key={message.id || index}
                      style={{
                        display: 'flex',
                        justifyContent: isMyMessage ? 'flex-end' : 'flex-start',
                        marginBottom: index === dateMessages.length - 1 ? 0 : '0.5rem'
                      }}
                    >
                      <div
                        style={{
                          maxWidth: '70%',
                          background: isMyMessage ? 'var(--primary)' : 'white',
                          color: isMyMessage ? 'white' : 'var(--dark)',
                          padding: '0.75rem',
                          borderRadius: '12px',
                          borderBottomRightRadius: isMyMessage ? '4px' : '12px',
                          borderBottomLeftRadius: isMyMessage ? '12px' : '4px',
                          boxShadow: '0 1px 2px rgba(0,0,0,0.1)',
                          position: 'relative'
                        }}
                      >
                        <div style={{ wordBreak: 'break-word' }}>{message.text}</div>
                        <div style={{
                          fontSize: '0.7rem',
                          marginTop: '0.25rem',
                          opacity: 0.7,
                          textAlign: 'right'
                        }}>
                          {formatTime(message.timestamp)}
                          {isMyMessage && (
                            <span style={{ marginLeft: '0.25rem' }}>
                              {message.read ? '✓✓' : '✓'}
                            </span>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            ))
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Форма отправки */}
        <form onSubmit={handleSendMessage} style={{
          padding: '1rem',
          borderTop: '1px solid var(--border)',
          background: 'white',
          display: 'flex',
          gap: '0.5rem'
        }}>
          <input
            type="text"
            value={newMessage}
            onChange={(e) => setNewMessage(e.target.value)}
            placeholder="Напишите сообщение..."
            style={{
              flex: 1,
              padding: '0.75rem',
              border: '1px solid var(--border)',
              borderRadius: '20px',
              outline: 'none',
              fontSize: '1rem'
            }}
            autoFocus
          />
          <button
            type="submit"
            disabled={!newMessage.trim()}
            style={{
              background: 'var(--primary)',
              color: 'white',
              border: 'none',
              borderRadius: '50%',
              width: '45px',
              height: '45px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              cursor: newMessage.trim() ? 'pointer' : 'not-allowed',
              opacity: newMessage.trim() ? 1 : 0.5
            }}
          >
            📤
          </button>
        </form>

        {/* Подсказка безопасности */}
        <div style={{
          padding: '0.5rem',
          fontSize: '0.8rem',
          color: 'var(--gray)',
          textAlign: 'center',
          background: '#fff3cd',
          borderTop: '1px solid #ffeeba'
        }}>
          ⚠️ Не переводите деньги напрямую продавцу. Все платежи только через баланс платформы.
        </div>
      </div>
    </div>
  );
}

export default ChatModal;