import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useUser } from '../context/UserContext';
import { useBalance } from '../context/BalanceContext';
import { useNotification } from '../components/Notification';

function UserProfile() {
  const { userId } = useParams();
  const navigate = useNavigate();
  const { users, getUserReviews, currentUser, createSupportTicket, isSupport, isAdmin } = useUser();
  const { transactions } = useBalance();
  const { showNotification } = useNotification();
  const [showAllReviews, setShowAllReviews] = useState(false);

  // Находим пользователя по ID
  const user = users.find(u => u.id === userId);

  if (!user) {
    return (
      <div style={{ textAlign: 'center', padding: '3rem' }}>
        <h2>😕 Пользователь не найден</h2>
        <p style={{ marginTop: '1rem', color: 'var(--gray)' }}>
          Возможно, пользователь был удален или ID указан неверно
        </p>
        <button 
          className="btn btn-primary" 
          onClick={() => navigate('/')}
          style={{ marginTop: '2rem', width: 'auto' }}
        >
          На главную
        </button>
      </div>
    );
  }

  // Получаем отзывы
  const reviews = getUserReviews(user.id);
  const displayedReviews = showAllReviews ? reviews : reviews.slice(0, 5);

  // Статистика
  const stats = user.stats || {
    totalTrades: 0,
    positiveReviews: 0,
    negativeReviews: 0,
    avgRating: 0
  };

  // Сделки пользователя
  const userTransactions = transactions.filter(t => 
    (t.type === 'purchase' && t.seller === user.username) ||
    (t.type === 'listing_created' && t.seller === user.username)
  );

  const handleContactSupport = () => {
    createSupportTicket({
      type: 'question',
      userId: currentUser.id,
      description: `Вопрос о пользователе ${user.username}`,
      status: 'open'
    });
    showNotification('Обращение создано. Мы свяжемся с вами в ближайшее время.', 'success');
  };

  return (
    <div>
      {/* Шапка профиля */}
      <div className="hero" style={{ padding: '2rem' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '2rem', flexWrap: 'wrap' }}>
          {/* Аватар */}
          <div style={{
            width: '100px',
            height: '100px',
            borderRadius: '50%',
            background: 'var(--gradient)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '2.5rem',
            color: 'white',
            border: user.role === 'support' ? '3px solid var(--success)' : 
                    user.role === 'admin' ? '3px solid var(--primary)' : 'none',
            position: 'relative'
          }}>
            {user.photoUrl ? (
              <img src={user.photoUrl} alt={user.username} style={{ width: '100%', borderRadius: '50%' }} />
            ) : (
              user.username[0].toUpperCase()
            )}
            {user.role === 'support' && (
              <div style={{
                position: 'absolute',
                bottom: '0',
                right: '0',
                background: 'var(--success)',
                color: 'white',
                borderRadius: '50%',
                width: '25px',
                height: '25px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '0.8rem',
                border: '2px solid white'
              }}>
                🛟
              </div>
            )}
          </div>

          {/* Информация */}
          <div style={{ flex: 1 }}>
            <h1 style={{ marginBottom: '0.5rem' }}>
              {user.firstName} {user.lastName}
              {user.role === 'admin' && ' 👑'}
              {user.role === 'support' && ' 🛟'}
              {user.id === currentUser?.id && ' (Вы)'}
            </h1>
            <p style={{ opacity: 0.9 }}>@{user.username}</p>
            <p style={{ opacity: 0.8, fontSize: '0.9rem' }}>
              На платформе с {user.registrationDate ? new Date(user.registrationDate).toLocaleDateString() : 'недавно'}
            </p>
            <p style={{ opacity: 0.8, fontSize: '0.9rem' }}>
              ID: {user.id}
            </p>
            {user.id !== currentUser?.id && (
              <button
                className="btn btn-outline"
                onClick={handleContactSupport}
                style={{ marginTop: '1rem', width: 'auto' }}
              >
                🛟 Связаться с поддержкой
              </button>
            )}
          </div>

          {/* Рейтинг */}
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '3rem', fontWeight: 'bold' }}>
              {stats.avgRating.toFixed(1)}
            </div>
            <div style={{ fontSize: '1.5rem', color: '#ffc107' }}>
              {'★'.repeat(Math.round(stats.avgRating))}
              {'☆'.repeat(5 - Math.round(stats.avgRating))}
            </div>
            <div>({reviews.length} отзывов)</div>
          </div>
        </div>

        {/* Статистика */}
        <div className="stats" style={{ marginTop: '2rem' }}>
          <div className="stat-item">
            <div className="stat-value">{userTransactions.length}</div>
            <div className="stat-label">Сделок</div>
          </div>
          <div className="stat-item">
            <div className="stat-value" style={{ color: 'var(--success)' }}>
              {stats.positiveReviews}
            </div>
            <div className="stat-label">Положительных</div>
          </div>
          <div className="stat-item">
            <div className="stat-value" style={{ color: 'var(--danger)' }}>
              {stats.negativeReviews}
            </div>
            <div className="stat-label">Отрицательных</div>
          </div>
        </div>

        {/* Кнопка назад, если это не текущий пользователь */}
        {user.id !== currentUser?.id && (
          <div style={{ marginTop: '1rem', textAlign: 'center' }}>
            <button 
              className="btn btn-outline" 
              onClick={() => navigate(-1)}
              style={{ width: 'auto' }}
            >
              ← Назад
            </button>
          </div>
        )}
      </div>

      {/* Отзывы */}
      <h2 className="section-title">Отзывы о пользователе</h2>

      {reviews.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
          <p>У пользователя пока нет отзывов</p>
        </div>
      ) : (
        <>
          <div className="reviews-list">
            {displayedReviews.map(review => {
              const reviewer = users.find(u => u.id === review.fromUserId);
              
              return (
                <div key={review.id} className="listing-card" style={{ marginBottom: '1rem' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                      <div 
                        className="avatar" 
                        style={{ 
                          width: '30px', 
                          height: '30px',
                          border: reviewer?.role === 'support' ? '2px solid var(--success)' : 
                                  reviewer?.role === 'admin' ? '2px solid var(--primary)' : 'none'
                        }}
                      >
                        {reviewer?.username?.[0] || '?'}
                      </div>
                      <div>
                        <strong 
                          onClick={() => navigate(`/user/${reviewer?.id}`)}
                          style={{ cursor: 'pointer' }}
                        >
                          {reviewer?.username || 'Пользователь'}
                          {reviewer?.role === 'support' && ' 🛟'}
                          {reviewer?.role === 'admin' && ' 👑'}
                        </strong>
                        <div style={{ fontSize: '0.8rem', color: 'var(--gray)' }}>
                          {new Date(review.date).toLocaleDateString()}
                        </div>
                      </div>
                    </div>
                    <div style={{ fontSize: '1.2rem', color: '#ffc107' }}>
                      {'★'.repeat(review.rating)}
                      {'☆'.repeat(5 - review.rating)}
                    </div>
                  </div>
                  
                  <p style={{ marginBottom: '0.5rem' }}>{review.comment}</p>
                  
                  {review.isDeleted && (
                    <p style={{ color: 'var(--danger)', fontSize: '0.9rem' }}>
                      ⚠️ Отзыв удален администрацией
                    </p>
                  )}
                </div>
              );
            })}
          </div>

          {reviews.length > 5 && !showAllReviews && (
            <button 
              className="btn btn-outline"
              onClick={() => setShowAllReviews(true)}
              style={{ marginTop: '1rem' }}
            >
              Показать все {reviews.length} отзывов
            </button>
          )}
        </>
      )}
    </div>
  );
}

export default UserProfile;