import React, { useState } from 'react';
import { useBalance } from '../context/BalanceContext';
import { useNotification } from '../components/Notification';

function Profile() {
  const { balance, transactions, withdraw, platformBalance } = useBalance();
  const { showNotification } = useNotification();
  const [withdrawAmount, setWithdrawAmount] = useState('');

  // Статистика пользователя
  const totalSpent = transactions
    .filter(t => t.type === 'purchase')
    .reduce((sum, t) => sum + t.price, 0);

  const totalEarned = transactions
    .filter(t => t.type === 'listing_created')
    .reduce((sum, t) => sum + t.price, 0);

  const handleWithdraw = () => {
    const amount = Number(withdrawAmount);
    
    if (amount < 100) {
      showNotification('Минимальная сумма вывода 100 ₽', 'error');
      return;
    }

    if (amount > balance) {
      showNotification('Недостаточно средств', 'error');
      return;
    }

    const result = withdraw(amount);
    if (result.success) {
      showNotification('Заявка на вывод создана', 'success');
      setWithdrawAmount('');
    }
  };

  return (
    <div>
      <h1 className="section-title">Профиль пользователя</h1>

      {/* Основная информация */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
        gap: '1.5rem',
        marginBottom: '2rem'
      }}>
        <div className="listing-card" style={{ textAlign: 'center' }}>
          <h3>Баланс</h3>
          <div style={{ fontSize: '2rem', fontWeight: 'bold', color: 'var(--primary)' }}>
            {balance.toLocaleString()} ₽
          </div>
        </div>

        <div className="listing-card" style={{ textAlign: 'center' }}>
          <h3>Потрачено</h3>
          <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--danger)' }}>
            {totalSpent.toLocaleString()} ₽
          </div>
        </div>

        <div className="listing-card" style={{ textAlign: 'center' }}>
          <h3>Заработано</h3>
          <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--success)' }}>
            {totalEarned.toLocaleString()} ₽
          </div>
        </div>
      </div>

      {/* Вывод средств */}
      <div className="form-container" style={{ marginBottom: '2rem' }}>
        <h2>Вывод средств</h2>
        <p style={{ marginBottom: '1rem', color: 'var(--gray)' }}>
          Доступно для вывода: {balance.toLocaleString()} ₽
        </p>
        
        <div style={{ display: 'flex', gap: '1rem' }}>
          <input
            type="number"
            className="search-input"
            placeholder="Сумма вывода"
            value={withdrawAmount}
            onChange={(e) => setWithdrawAmount(e.target.value)}
            min="100"
            max={balance}
          />
          <button 
            className="btn btn-primary"
            onClick={handleWithdraw}
            style={{ width: 'auto' }}
          >
            Вывести
          </button>
        </div>
        <p style={{ marginTop: '0.5rem', fontSize: '0.9rem', color: 'var(--gray)' }}>
          Минимальная сумма: 100 ₽. Вывод на карту или криптокошелек.
        </p>
      </div>

      {/* История транзакций */}
      <h2>История операций</h2>
      <div style={{ marginTop: '1rem' }}>
        {transactions.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '2rem', color: 'var(--gray)' }}>
            <p>Нет операций</p>
          </div>
        ) : (
          transactions.map(t => (
            <div key={t.id} className="listing-card" style={{ marginBottom: '1rem' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <div>
                  <strong>
                    {t.type === 'deposit' && '💰 Пополнение'}
                    {t.type === 'purchase' && '🛒 Покупка'}
                    {t.type === 'listing_created' && '📢 Создание объявления'}
                    {t.type === 'withdraw' && '💳 Вывод'}
                  </strong>
                  <p style={{ fontSize: '0.9rem', color: 'var(--gray)' }}>
                    {new Date(t.date).toLocaleString()}
                  </p>
                </div>
                <div style={{ 
                  fontSize: '1.2rem',
                  fontWeight: 'bold',
                  color: t.type === 'deposit' || t.type === 'listing_created' 
                    ? 'var(--success)' 
                    : 'var(--danger)'
                }}>
                  {t.type === 'deposit' || t.type === 'listing_created' ? '+' : '-'}
                  {t.amount || t.price} ₽
                </div>
              </div>
              {t.commission && (
                <p style={{ fontSize: '0.9rem', color: 'var(--gray)', marginTop: '0.5rem' }}>
                  Комиссия платформы: {t.commission} ₽
                </p>
              )}
            </div>
          ))
        )}
      </div>

      {/* Информация о платформе (для админов) */}
      {platformBalance > 0 && (
        <div style={{ marginTop: '2rem', padding: '1rem', background: '#f5f5f5', borderRadius: '8px' }}>
          <h3>Баланс платформы (5% комиссия)</h3>
          <p style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--primary)' }}>
            {platformBalance.toLocaleString()} ₽
          </p>
        </div>
      )}
    </div>
  );
}

export default Profile;